INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbub0002qyd5dyhmr0l4', 'annette', 'Annette', 'Passive', 'Whisperwind', 'Gains Mana and increased cooldown speed while moving. If there are teammates nearby, also gains Movement Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbud0004qyd54eugcjqu', 'annette', 'Annette', 'Ultimate', 'Hurricane Wall', 'Conjures a barrier around herself, knocking back enemies and dealing damage. Enemies that touch the barrier take damage and are stunned. Teammates within the barrier gain crowd control immunity.
Untargetable while channeling.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbuj000bqyd5qv8h303t', 'ata', 'Ata', 'Passive', 'Child of the Sea', 'Loss of life is temporarily stored in a gray shield form, during which 40%/15% of the equivalent gray shield of damage dealt to heroes/non-heroes is converted into blood, scaling up based on extra life. Basic attacks come with additional physical damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbul000dqyd584gcgtgo', 'ata', 'Ata', '1', 'Wavewalking', 'Endeavor to jump up and deal physical damage to smashed enemies when you land. Afterwards, bounce up again, dealing the same damage as well as a 0.5 second knockback effect when you land. Immunity to control during the jump. When attacking multiple enemies at once, damage decays by 20% for each additional enemy, down to 60%. Increases damage to minions by an additional 30%.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbum000fqyd5oxlsclow', 'ata', 'Ata', '2', 'Sea Anchor', 'Throw the anchor straight out to hit enemies in front of you, dealing physical damage and 60% slow for 1.5 seconds. If the anchor is embedded in a wall, Ata will use the force to dash himself and the enemy to that spot. When it hits the wall, it deals Physical damage and stuns for 0.5 seconds. [Passive]: after using [Anchor], the next basic attack within 3 seconds will pull the enemy back with the anchor.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbum000hqyd5dqeql91t', 'ata', 'Ata', 'Ultimate', 'Ghost Ship', 'Ata builds temporary terrain along the outer border of a fan-shaped targetarea, dealing damage to enemies within it.Gains crowd control immunity while using the skill.He can use the skill again to make the temporary terrain disappear early.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbv10014qyd59e32txs8', 'butterfly', 'Butterfly', 'Passive', 'Assassination', 'Butterfly gains 2 stacks of mark from defeating heroes and 1 stack fromassisting or killing monsters/minions. At 3 stacks, the next skill used willnot enter cooldown.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbv10016qyd5urskhvsd', 'butterfly', 'Butterfly', '1', 'Whirlwind', 'Butterfly deals damage to enemies around her and gains a shield. HerMovement Speed increases during this time.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbv20018qyd5n6q1vs75', 'butterfly', 'Butterfly', '2', 'Sword Propel', 'Butterfly deals damage in the target direction and inflicts slow.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbv3001aqyd5jyzy0r32', 'butterfly', 'Butterfly', 'Ultimate', 'Death Dealer', 'Butterfly jumps to the target and deals damagelf the target is defeated within a certain period of time, the cooldown of thisskill is refreshed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbvd001xqyd5vivnl7ch', 'devara', 'Devara', 'Passive', 'Wish of the Living', 'Devara''s Basic Attacks grant Energy. Becomes enhanced and gains another basic skill chance upon reaching the limit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbve001zqyd5bra2ngpl', 'devara', 'Devara', 'Ultimate', 'Millennium Echo', 'Gains crowd control immunity and a Movement Speed boost. Upon landing, enhances Basic Attack. Basic Attacks grant Energy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbvp002kqyd5iy7tip3w', 'fatih', 'Fatih', 'Passive', 'Only the Strong (Fatih)', 'Enhance Recovery Whenever he uses a skill, gains an enhanced Basic Attack that unleashes sword energy. Enhanced Basic Attacks have higher Attack Speed and restore Health. While using Sacred Tree Blessing, enhanced Basic Attacks unleash 1 additional blast of sword energy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbvp002mqyd5znre2uc9', 'fatih', 'Fatih', '1', 'The King''s Blade', 'Damage Movement Crowd Control Dashes forward to deal damage. The 3rd skill use also launches the enemy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbvq002oqyd52er8tpls', 'fatih', 'Fatih', '2', 'The King''s Return', 'Damage Slow Unleashes sword energy, dealing damage to enemies and slowing them. Recovers Health if he hits a hero. While using Sacred Tree Blessing, he unleashes 1 additional blast of sword energy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbvq002qqyd5w99o8r09', 'fatih', 'Fatih', 'Ultimate', 'Sacred Tree Blessing', 'Enhance Purify Recovery Removes all crowd control effects on himself, dealing physical damage to nearby enemies and gaining max Health. Boosts the effects of Skill 2 and enhanced Basic Attacks while this skill is active. Tap again to end the skill.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbw0003dqyd5v8dtkteo', 'florentino', 'Florentino', 'Passive', 'Shuffle', 'After leaving combat or touching a bouquet, enhances the next Basic Attack to include a dash and deal extra damage. If the attack hits a hero, recovers Health. He can dash again after the initial dash.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbw0003fqyd5ng7vretk', 'florentino', 'Florentino', 'Ultimate', 'Gentlemen''s Duel', 'Dashes forward and marks the first target, increasing their damage taken, then scatters bouquets. While the skill is active, recovers twice as much Health and gains crowd control immunity. He can dash again after the initial dash.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbw6003qqyd56wygntqn', 'flowborn-mage', 'Flowborn (Mage)', 'Passive', 'Flow of the World', 'Can change Flow states at the Base to enhance stats.
Spends 1 stack of Flow to perform an enhanced Basic Attack that deals area damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbw6003sqyd5f482a58w', 'flowborn-mage', 'Flowborn (Mage)', '1', 'Convergence', 'Channels the Flow, reducing the cooldown of other skills by 50%. Also gains 5–9 stacks of Flow based on the number of nearby heroes and minions and recovers Health based on Flow stacks.
Damages and knocks back nearby enemies (without applying crowd control).', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbw7003uqyd5ei2l91em', 'flowborn-mage', 'Flowborn (Mage)', '2', 'Flow Formation', 'Deals damage and slows enemies within range, then deals damage over time.
Using the skill repeatedly within a short time enhances it, dealing damage and launching or stunning enemies. When new magic circles overlap with the initial one, they increase its damage and refresh its duration.
Can spend 4 stacks of Flow to use the skill without triggering cooldown.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbw7003wqyd5jqh4kan4', 'flowborn-mage', 'Flowborn (Mage)', 'Ultimate', 'Arcane Arts', 'Continuously channels a beam to deal damage over time.
While the beam is linked with a hero, continuously throws Energy Bombs that deal area damage.
Can spend 5 stacks of Flow to stop the skill from entering cooldown after this use.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbwg004jqyd5rxrrbja7', 'flowborn-tank', 'Flowborn (Tank)', 'Passive', 'Flow of the World', 'Can change Flow states at the Base to enhance stats.
Vitality: Increases max Health and Physical and Magical Defense.
Piercing Heart: Increases max Health and Physical Attack.
Haste: Increases max Health and Movement Speed.
Focus: Increases max Health and Cooldown Reduction.
Spend 1 stack of Flow to perform an enhanced Basic Attack and deal damage and gain recovery.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbwh004lqyd5vhsqbyuc', 'flowborn-tank', 'Flowborn (Tank)', '1', 'Convergence', 'Channels the Flow, reducing the cooldown of other skills by 50%. Also gains 5–9 stacks of Flow based on the number of nearby heroes and minions and recovers Health based on Flow stacks.
Damages and knocks back nearby enemies (without applying crowd control).', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbwh004nqyd54j63xu99', 'flowborn-tank', 'Flowborn (Tank)', '2', 'Power From Within', 'Charges at the target and slashes, dealing damage, launching enemies, and gaining a shield.
Using the skill continuously over a short time converts it to Clearing Slash and Rifting Slash.
If the skill is not on cooldown, spend 4 stacks of Flow to stop it from entering cooldown after use.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbwi004pqyd558mgaj1a', 'flowborn-tank', 'Flowborn (Tank)', 'Ultimate', 'All In', 'Leaps to the target location and attacks, dealing damage and launching enemies.
If the skill is not on cooldown, spend 5 stacks of Flow to stop it from entering cooldown after this use.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbwr005eqyd5quhjvsrd', 'garuda', 'Garuda', 'Passive', 'Keen Feathers', 'Damage Basic Attacks can pierce and deal damage to enemies in their path.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbws005gqyd5bdkeko63', 'garuda', 'Garuda', '1', 'Arrows of Gold', 'Damage Slow Conjures an arrow formation that deals continuous damage to targets within range while slowing them.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbwu005iqyd5wgautxsi', 'garuda', 'Garuda', '2', 'Golden Winged Blessing', 'Speed Up Shield Damage Gains Movement Speed and a shield while dealing damage to nearby enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbwv005kqyd5njo2q89g', 'garuda', 'Garuda', 'Ultimate', 'Wings of Judgment', 'Damage Speed Up Sends arrows surging forward, dealing damage. Using the skill again shoots all remaining arrows, damaging nearby enemies, inflicting them with Dread, and removing all Physical Attack bonuses granted by their equipment.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbx50069qyd5oqtxy86x', 'lapulapu', 'Lapulapu', 'Passive', 'Sea Beast''s Favor', 'Enhance Increases the Physical and Magical Defense of himself and the teammate with the lowest Health nearby.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbx6006bqyd57z4pskur', 'lapulapu', 'Lapulapu', '1', 'Torrential Blade', 'Damage Imperil Damages and slows enemies within range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbx7006dqyd5yxgqiuej', 'lapulapu', 'Lapulapu', '2', 'Island''s Blessing', 'Crowd Control Damage Movement Dashes in the target direction, dealing damage to enemies in his path and launching them.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbx7006fqyd5c7c83tn6', 'lapulapu', 'Lapulapu', 'Ultimate', 'Raging Sea', 'Crowd Control Damage Slow Splits the earth, damaging enemies within range and launching them. The fractured earth damages and slows enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbxg0072qyd546ztg1wp', 'lorion', 'Lorion', 'Passive', 'Eternal', 'Skill 2 or Ultimate hits also damage units near the target.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbxh0074qyd5q5vw42i4', 'lorion', 'Lorion', 'Ultimate', 'Darkness Falls', 'Flies toward the projectile.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbxk007bqyd5qmmqc7nz', 'luara', 'Luara', 'Passive', 'Serpent''s Envoy', 'Basic Attacks unleash serpent blades to deal damage, reducing Skill 1''s cooldown for every enemy hit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbxl007dqyd5kipap1iq', 'luara', 'Luara', '1', 'Deadly Fang', 'Activates a serpent blade and gains Movement Speed. She can quickly scale walls should she run into them during this period.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbxl007fqyd53u0ig20b', 'luara', 'Luara', '2', 'Furtive Attack', 'Summons the Fire Serpent at the target location, which then moves toward her, damaging and slowing enemies in its path. If serpent blades are active, it deals additional damage to enemies. If not, the cooldown is reduced.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbxm007hqyd5gti34vth', 'luara', 'Luara', 'Ultimate', 'Blazing Glare', 'Releases the Fire Serpent in the target direction, dealing damage and blinding enemies in its path, and gains a serpent blade. During this time, both attacking and being attacked will accumulate Fury. At full Fury, deals area damage and launches enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbxw0088qyd553c1xjr5', 'agudo', 'Agudo', 'Passive', 'Mountain Encounter', 'Replaces Recovery with Release. Upon releasing monsters, they grant her Gold, EXP, and their respective blessing. Her Basic Attacks drop Seed Mines around enemy targets.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbxw008aqyd5154w1g08', 'agudo', 'Agudo', '1', 'Wild Growth', 'Grants Movement Speed and Health recovery to allied units in the target area. Additionally, she gains Attack Speed and summons multiple monsters at the center.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbxx008cqyd5dg96xjc7', 'agudo', 'Agudo', '2', 'Tumble, Furball!', 'Rolls forward, dealing damage to nearby enemies. Gains immunity against 1 hard crowd control, and damages and launches enemies hit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbxx008eqyd5yfpiuhn3', 'agudo', 'Agudo', 'Ultimate', 'Seed Mines', 'Agudo rolls forward and enhances her next Basic Attack to drops 3 Seed Mines and deal Physical Damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbxy008gqyd52ednfbjs', 'agudo', 'Agudo', 'Ultimate', 'Gorge Mobilization', 'Summons Furball to leap to the target location, inflicting damage and crowd control. Furball then fights independently.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbxy008iqyd5k2mukngw', 'agudo', 'Agudo', 'Ultimate', 'Recall', 'Recall Furball', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzby80097qyd5radyi1wf', 'alessio', 'Alessio', 'Passive', 'Rebellious Little Hawk', 'Alessio''s Basic Attacks deal area damage, plus extra physical damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzby80099qyd53v42th08', 'alessio', 'Alessio', '1', 'Upgraded Shell', 'Enhances his next 3 Basic Attacks, which deal extra physical damage in a greater area.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzby8009bqyd58ul5hhbb', 'alessio', 'Alessio', '2', 'Legendary Hero Debut', 'Throws a smoke bomb, creating a cloud of smoke that grants Stealth toteammates within it, including himself. The bomb''s explosion sends himairborne, and his Basic Attacks allow him to stay airborne longer.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzby9009dqyd5ht8el0qw', 'alessio', 'Alessio', 'Ultimate', 'Sunset Fireworks Show', 'Leaps into the air and fires several shells, each shell dealing physical damage to the target in the area. Up to 1 enemy can take a shell for the target.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbyg009wqyd5qfxzhcml', 'allain', 'Allain', 'Passive', 'Howling Blade', 'Basic Attacks and skills grant Fury, which increases his Physical and Magical Pierce and grants damage reduction. At max Fury, he recovers Health, and the lower his Health, the more he recovers.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbyg009yqyd5tw6cl1c2', 'allain', 'Allain', '1', 'Meteor Kill', 'Based on how many stacks of mark he has, Allain deals damage multiple times in the target direction and launches enemies. He gains marks by hitting enemies with Basic Attacks and Ultimate.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbyg00a0qyd5zu71wexq', 'allain', 'Allain', '2', 'Moonlight Flash', 'Dashes in the target direction, damaging and slowing enemies. He gains Movement Speed and his next 3 Basic Attacks gain increased Attack Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbyh00a2qyd5hsih764j', 'allain', 'Allain', 'Ultimate', 'Death at Sunset', 'Allain leaps toward the targeted enemy hero and becomes untargetable. After a short delay, he lands and deals area damage. For every enemy hero hit, he gains marks and Fury.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbyr00arqyd5xvgyyyut', 'angela', 'Angela', 'Passive', 'Flame Incantation', 'Every time she damages an enemy with a skill, she increases her Movement Speed, and the enemy will take more damage from her subsequent skills.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbys00atqyd50nqrudfb', 'angela', 'Angela', '1', 'Scorching Barrage', 'Unleashes fireballs at the target area that deals multi-phase damage toenemy heroes.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbys00avqyd5c44vw2ar', 'angela', 'Angela', '2', 'Chaos Cinder', 'Hurls a fireball at the target location that turns into a firestorm when it hitsan enemy or reaches its max range, slowing and dealing damage to nearbyenemies.Any enemy that is hit directly by the fireball is stunned.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbyt00axqyd5af4fvs9y', 'angela', 'Angela', 'Ultimate', 'Blazing Brilliance', 'Channels a blazing beam in the target direction, dealing damage over timeGains a shield and immunity while the shield is active.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbz100bmqyd5gb835ltm', 'aoyin', 'Ao''yin', 'Passive', 'Hidden Dragon', 'The Dragon Souls from his last 2 skill uses grant effects to his Basic Attacks, which deal physical damage to up to two enemies. He gains 1 mark upon using skills, for up to 3 marks. Basic Attacks expend all marks for various effects, striking once per mark.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbz200boqyd5k2jt0ee2', 'aoyin', 'Ao''yin', '1', 'Flaming Palm', 'Deals physical damage and true damage. Attaches a Fire Dragon Soul to his sword. Basic Attacks deal more damage when this Soul is attached. Enhanced Basic Attacks will deal both physical damage and true damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbz200bqqyd5di0jls0s', 'aoyin', 'Ao''yin', '2', 'Downpour', 'Deals physical damage and recovers Health upon hit. Attaches a Water Dragon Soul to his sword. Basic Attacks restore Health and Mana when this Soul is attached. Enhanced Basic Attacks will deal physical damage and restore Health, but restore less for hits on non-hero units.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbz300bsqyd5xilvt53g', 'aoyin', 'Ao''yin', 'Ultimate', 'Riding the Wind', 'Gains Movement Speed that diminishes over time, deals physical damage, and knocks back enemies. Attaches a Wind Dragon Soul to his sword. Gains Movement Speed while this Soul is attached, 50% extra if on both swords. Enhanced Basic Attacks will deal physical damage and knock back enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbz300buqyd51r3bcsib', 'aoyin', 'Ao''yin', 'Ultimate', 'Infinite Vastness', 'Soars into the sky for up to 4.5s, then dives forward to damage and slow enemies. Landing deals equal damage and applies Dread. Gains Attack Speed and Attack Range. Basic Attacks hit 2 more enemies. Can switch Dragon Souls mid-flight.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbzc00cjqyd5h7ky89tk', 'arke', 'Arke', 'Passive', 'Kiss of Death', 'Attacks launched from the front of the target will not crit, but backstabs are guaranteed to crit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbzc00clqyd588huddz4', 'arke', 'Arke', '1', 'Arclight', 'Arke attacks twice in a row, dealing physical damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbzc00cnqyd5jcarnp6b', 'arke', 'Arke', '2', 'Untouchable', 'Arke dashes forward and attacks, marking an enemy while dealing physical damage and gaining Attack Speed. Attacking marked targets slows them and reduces this skill''s cooldown. She takes less damage from marked targets.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbzd00cpqyd5uhgc0uhr', 'arke', 'Arke', 'Ultimate', 'Phantom Dance', 'Enters stealth, gaining a Movement Speed boost and Health recovery. Enhances attack after exiting stealth, granting extra Movement Speed boost when dealing damage, and refreshes all skill cooldowns with defeats and assists.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbzk00d6qyd58i2moo5u', 'arli', 'Arli', 'Passive', 'Falling Leaves', 'Basic Attack hits place marks on the target. At max marks, damage is dealt to them.Using skills grants a follow-up Basic Attack.Gains Move Speed and reduces attack interval while parasol is away.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbzk00d8qyd5no4y9zzt', 'arli', 'Arli', '1', 'Lithe Step', 'Shifts in the target direction.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbzl00daqyd54ib0argd', 'arli', 'Arli', '2', 'Maple Dance', 'Knocks down nearby projectiles within a certain range and deals 2 strikes ofdamage to the enemy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbzl00dcqyd59i2vwccy', 'arli', 'Arli', 'Ultimate', 'Autumn Storm', 'Knocks back enemies in the target area and deals damage', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbzt00e1qyd5gt310vp8', 'arthur', 'Arthur', 'Passive', 'Holy Vanguard', 'Invokes the protection of the divine light to recover Health continuously. If Movement Speed is impaired, the Health restored is doubled.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbzt00e3qyd5ka2rkw4o', 'arthur', 'Arthur', '1', 'Valiant Charge', 'Enhances the next Basic Attack into a dash, dealing extra damage and silencing enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbzu00e5qyd5nclxz6ec', 'arthur', 'Arthur', '2', 'Whirling Strike', 'Deals damage over time to nearby enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzbzu00e7qyd55o7b45uy', 'arthur', 'Arthur', 'Ultimate', 'Might of Excalibur', 'Jumps to the target enemy hero to deal damage. Launches all heroes within range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0200eqqyd5xpe4w9uy', 'athena', 'Athena', 'Passive', 'Divine Awakening', 'Able to move in true form after dying. Deals damage and launches enemies in range when resurrected.Deals extra damage to non-hero units.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0200esqyd5vii2b8z3', 'athena', 'Athena', '1', 'Holy Advance', 'Dashes ahead with shield up, knocking back the enemy and dealing damagewhile gaining a shield that grants crowd control immunity.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0200euqyd5y38bb4ph', 'athena', 'Athena', '2', 'Unstoppable Spear', 'Shifts in the target direction and enhances the next Basic Attack, chargingand dealing damage to the enemy. Hitting the same target 3 timessuccessively deals extra damage equal to lost Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0300ewqyd55bu7qqqg', 'athena', 'Athena', 'Ultimate', 'Immovable Aegis', 'Raises a shield that grants crowd control immunity. Damage taken while theshield is up will be returned after a brief delay, dealing damage to enemieswithin range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0900fdqyd5nagr2s27', 'augran', 'Augran', 'Passive', 'Soul Resonance', 'Basic Attacks can connect to an enemy''s soul, dealing damage continuously unless the enemy breaks free. When the connection ends, it deals a large amount of damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0a00ffqyd5tk9po51e', 'augran', 'Augran', '1', 'Path of Passing', 'Slashes open a path to the afterlife, dealing damage to enemies hit. The path accelerates when it hits walls or the Life-Death Border, then deals extra damage. By traversing on the path, he can ignore terrain and gain Movement Speed. Hitting a wall for the first time generates an afterlife bridge, and he gains Movement Speed when crossing the bridge while enemies nearby are slowed. Using this skill again causes him to enter the Seer State.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0a00fhqyd5bwlm79cr', 'augran', 'Augran', '2', 'Death''s Precipice', 'Deals damage and inflicts slow on enemies to the front, then generates a Life-Death Border which damages, slows, and marks enemies who touch it. His next Basic Attack additionally attacks up to 3 marked targets, dealing extra damage and recovering his Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0b00fjqyd58k9m104y', 'augran', 'Augran', 'Ultimate', 'Conductor of Souls', 'Descends from the sky, damaging and knocking back nearby enemies. Hitting an enemy hero will recover his Health and summon their spirit counterpart to assist him. Enters the Seer State after, in which his Basic Attacks will kill targets with low Health instantly.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0j00g8qyd56zmmgj7a', 'bai-qi', 'Bai Qi', 'Passive', 'Reaper''s Revenge', 'Enhance Speed Up Gains Energy when dealing or taking damage, increasing his Movement Speed and enhancing his recovery effects.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0k00gaqyd5gswm11g3', 'bai-qi', 'Bai Qi', '1', 'Blood Echo', 'Damage Recovery Deals damage to nearby enemies and recovers Health. Charging up will boost the skill''s effects. ''''''Passive:'''''' When taking damage, there is a chance to automatically trigger Skill 1.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0k00gcqyd50ulkffkd', 'bai-qi', 'Bai Qi', '2', 'Deathscythe', 'Crowd Control Damage Enhance Summons a scythe in the target direction, pulling enemies within range while inflicting damage and slow.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0k00geqyd5esjersrw', 'bai-qi', 'Bai Qi', 'Ultimate', 'Lay Waste', 'Crowd Control Damage Enhance Leaps to the target location and taunts enemies while dealing damage and enhancing his recovery effects. Taunt duration increases with Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0r00gxqyd5cxhscih6', 'biron', 'Biron', 'Passive', 'Fearless Chariot', 'Accumulates charge when Basic Attacks or unenhanced skills land hits, for up to 3 bars of charge.While having at least 1 bar, Basic Attack hits recover Health.Using Skill 1, the Ultimate, or an enhanced Basic Attack from Skill 2 will spend 1 bar.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0s00gzqyd5i1y4ew7m', 'biron', 'Biron', '1', 'Electrifying Charge', 'Swings his weapon twice in the target direction, dealing damage andrecovering Health with every hit.While charged, deals more damage and recovers more Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0t00h1qyd5brfonzci', 'biron', 'Biron', '2', 'Storm Strike', 'Dashes in the target direction, dealing damage to enemies in his path whilegaining an enhanced Basic Attack that deals damage and slows targetsWhile charged, the next Basic Attack deals more damage, and the sloweffect is changed to a launch effect.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc0t00h3qyd5t9pwm5i4', 'biron', 'Biron', 'Ultimate', 'Force Field Suppression', 'Gains a shield while damaging and slowing nearby enemiesWhile charged, the skill deals more damage, grants a stronger shield, andproduces a spark that deals damage to nearby enemies while stealingMovement Speed from enemy heroes.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1200hsqyd5oiqdy5a8', 'cai-yan', 'Cai Yan', 'Passive', 'Can''t Touch This', 'Periodic Passive Effect: Restores Health and gains a Movement Speedbonus when taking damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1300huqyd5kyg9uzh7', 'cai-yan', 'Cai Yan', '1', 'Healing Hymn', 'Continuously restores Health to nearby allies in range while gaining', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1300hwqyd5ocbwdjh5', 'cai-yan', 'Cai Yan', '2', 'Earworm', 'Fires a sound wave in the target direction, stunning and dealing damage to enemies hit. Sound waves bounce between nearby enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1400hyqyd5513hf6fq', 'cai-yan', 'Cai Yan', 'Ultimate', 'Tune of Tranquility', 'Continuously heals the nearby ally with the lowest Health within rangewhile granting them increased Physical and Magical Defense.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1900i7qyd58nw12nix', 'chano', 'Chano', 'Passive', 'Hunting', 'Whenever he moves through brush, gains Movement Speed and enhances his next Basic Attack to a double shot that deals extra damage. Leaps when emerging from brush.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1a00i9qyd5qz45mpte', 'chano', 'Chano', '1', 'Soaring Signal', 'Leaps into the air, gaining Movement Speed and allowing him to traverse terrain. While airborne, his Basic Attack fires a powerful arrow, dealing physical damage and knocking back enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1a00ibqyd5b1tkszhz', 'chano', 'Chano', '2', 'Lupine Trap', 'Throws a wolf spirit trap at a target location. When triggered, it deals physical damage and summons a wolf spirit to attack the enemy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1a00idqyd5f4qpcggs', 'chano', 'Chano', 'Ultimate', 'Leader Stance', 'Summons wolf spirits and gains the ability to shoot while moving. Also boosts Physical Attack, Movement Speed, and Attack Speed for 8s.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1k00j2qyd5j65gm187', 'charlotte', 'Charlotte', 'Passive', 'SPLASH GRADATION', 'After any skill hits an enemy, her next different skill used will be enhanced to a follow-up skill. Additionally, gains 1 stack of mark, for up to 5 stacks. Consuming 3 stacks will enhance her next Basic Attack.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1l00j4qyd5r8afu3wc', 'charlotte', 'Charlotte', '1', 'TRI-SLASH (Initial)', '''''''Initial Skill:'''''' After a short delay, releases TRI-SLASH in the target direction, dealing damage to enemies and increasing her Movement Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1l00j6qyd5ofrzdkx3', 'charlotte', 'Charlotte', '2', 'SPLASH FOUNT (Initial)', '''''''Initial Skill:'''''' Dashes in the target direction, while striking several times. Recovers Health each time damage is dealt.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1m00j8qyd5oq4tfvc6', 'charlotte', 'Charlotte', 'Ultimate', 'POWER GRADATION (Initial)', '''''''Initial Skill:'''''' Carves a seven-pointed star around her, dealing damage and slowing nearby enemies. Gains crowd control immunity and damage reduction while the skill is active.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1m00jaqyd59qtfq5eq', 'charlotte', 'Charlotte', 'Ultimate', 'TRI-SLASH (Follow-up)', '''''''Follow-up Skill'''''': After a shorter delay, unleashes TRI-SLASH, dealing higher damage to enemies and increasing her Movement Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1m00jcqyd5aldq33re', 'charlotte', 'Charlotte', 'Ultimate', 'SPLASH FOUNT (Follow-up)', '''''''Follow-Up Skill:'''''' Dashes in the target direction while striking several times. Recovers Health each time damage is dealt.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc1n00jeqyd5zy364a8r', 'charlotte', 'Charlotte', 'Ultimate', 'POWER GRADATION (Follow-up)', '''''''Follow-up skill:'''''' Carves a seven-pointed star more quickly, dealing damage and slowing enemies. Gains crowd control immunity and damage reduction while the skill is active. When the star is formed, deals extra damage and launches enemies in the center.', '[]', '[]', NULL, NULL, '', '');
