INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc3m00piqyd5thu3pct9', 'dian-wei', 'Dian Wei', 'Ultimate', 'Leap of Fury', 'Jumps to the target,damaging and slowing them while enhancing himself.While enhanced,deals extra true damage to enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc3r00pxqyd5u1rclhge', 'diaochan', 'Diaochan', 'Passive', 'Explosion of Fragrance', 'Applies stacks to the opponent. At max stacks, inflicts AoE damage and slow while restoring Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc3s00pzqyd5ejab69zl', 'diaochan', 'Diaochan', '1', 'Returning Lotus', 'Sends out a lotus in a direction that returns to her when it reaches its max distance, damaging enemies in its path.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc3s00q1qyd5p12rywo9', 'diaochan', 'Diaochan', '2', 'Petals in the Wind', 'Dashes in the target direction, during which she is untargetable. Launches orbs to attack nearby enemies, dealing damage and reducing the cooldown of Skill 2.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc3t00q3qyd5pmgfrfef', 'diaochan', 'Diaochan', 'Ultimate', 'Flowery Potential', 'Diaochan conjures up a magic circle around her, which lasts for a period oftime. While she is within the circle, the cooldowns of Skill 1 and Skill 2 aresped up. The circle deals damage to enemies within it when it is generatedand when it expires.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4200qsqyd59kb9n58z', 'dolia', 'Dolia', 'Passive', 'Mermaid''s Gift', 'Dolia takes on mermaid form when in water (rivers are also considered water), reducing the slows taken by 50% and returning life and mana every second. The mermaid form''s Basic Attacks will shoot water arrows for ranged damage. Dolia''s [Recovery] is replaced with [Mermaid''s Gift], which allows her to create a pact with a selected teammate, and prioritizes her pacted teammate when using [Celestial Melody].', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4300quqyd555624bn8', 'dolia', 'Dolia', '1', 'Ode', 'Dolia chants 4 sound waves that spread outward, the first 3 dealing spell damage and 10% slow. The 4th deals more spell damage and 50% slow for 1 second. The sound waves also echo when they hit an enemy, dealing spell damage to those they touch and, if released in water, sending waves of water knocking back nearby enemies (knockback of enemies around you has a stun effect). Non-heroic units provoke a much smaller echo, dealing only 50% of the damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4300qwqyd5cp7z8w8h', 'dolia', 'Dolia', '2', 'Wavemaker', 'Lam enters “Submerged” state, greatly increasing his Movement Speed for 3 seconds. When the duration ends, Lam leaps out of the water, immediately restoring 50% of this skill’s cooldown. While in Submerged state, casting the skill again will cause Lam to surface early, dealing 300 (+120% Bonus Physical Attack) Physical Damage to nearby enemies and slowing their Movement Speed by 50% for 1.5 seconds. Passive: While in river terrain, the Submerged state has no time limit. If an enemy hero with below 30% Health appears within 1500 range, Lam gains 450 Movement Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4400qyqyd55x7pilr2', 'dolia', 'Dolia', 'Ultimate', 'Celestial Melody', 'After Dolia briefly chants, refresh the skill with the longest current cooldown of a friendly within range, taking more cooldown from yourself. If a teammate''s skill is not used after being refreshed, [Celestial Melody]''s cooldown recovery speed can be accelerated by 20/30/40%. Teammates do not consume Mana or Energy when using the skill for 5 seconds after the skill is refreshed, and the beatdown benefit caused by the skill is split equally with Dolia. Refreshing skills for contracted teammates is prioritized, followed by non-contracted teammates, or refreshing your own skills if there are no teammates nearby. Failure to refresh a skill returns most of the cooldown of [Celestial Melody].', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4e00rpqyd5gwvv63a2', 'donghuang', 'Donghuang', 'Passive', 'Soul Sacrifice', 'Every time a dark orb passes through an enemy, it damages and restores Health to him.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4e00rrqyd50pr0o4dh', 'donghuang', 'Donghuang', '1', 'Eclipse', 'Deals damage to enemies in range and summons a dark orb. Donghuang can have up to have 3 dark orbs at a time. Hitting enemies with this skill reduces its cooldown.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4f00rtqyd5mwa6qedq', 'donghuang', 'Donghuang', '2', 'Dark Impact', 'Unleashes up to 3 dark orbs at the target location, increasing own Movement Speed and dealing damage to enemies in range. The 1st and 2nd dark orbs slow enemies. The 3rd dark orb stuns enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4f00rvqyd53bqeslfa', 'donghuang', 'Donghuang', 'Ultimate', 'Forsaken Contract', 'Suppresses an enemy hero and summons 3 dark orbslf he or the target is damaged during suppression, the other will take thesame amount of damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4m00sgqyd5f3xyr8cv', 'dr-bian', 'Dr Bian', 'Passive', 'Malicious Practice', 'Damage from skills and Basic Attacks places up to 5 marks on enemies each stack dealing damage over time.Chemist''s Skill 2 and Ultimate grant up to 5 marks to himself and histeammates, continually restoring Health with each stack.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4m00siqyd5g1hc48bq', 'dr-bian', 'Dr Bian', '1', 'Deadly Panacea', 'Throws a vial of deadly poison at the target location, dealing damage overtime and slowing enemies within range.Deadly Panacea: Can store up to three vials.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4n00skqyd582vsk7d0', 'dr-bian', 'Dr Bian', '2', 'Fatal Diagnosis', 'Launches a concoction in the target direction that deals damage to enemiesin its path and marks them.Restores Chemist and his allies'' Health and marks them.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4n00smqyd5hdg3l98c', 'dr-bian', 'Dr Bian', 'Ultimate', 'Master of Life', 'Damages enemies within range and heals teammatesEvery mark detonated will increase damage and healing.He recovers extra Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4u00t7qyd52cd74dv4', 'dun', 'Dun', 'Passive', 'Unyielding Might', 'Periodic Passive Effect: When Health drops too low, taking damage will enhance Dun. While enhanced, hits from skills and Basic Attacks recover Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4v00t9qyd5h71bgk65', 'dun', 'Dun', '1', 'Wind Slash', 'Slashes in the target direction, dealing damage to enemies within range and slowing them. If the skill hits an enemy hero, it can be used again before going into cooldown, dealing damage to enemies in range and launching them.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4v00tbqyd58ijrxp0d', 'dun', 'Dun', '2', 'Gale''s Benediction', 'Deals damage to enemies in range and grants shieldEnhances the next 3 Basic Attacks, dealing extra true damageEvery enhanced Basic Attack reduces the cooldown of Unruly Blade', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc4w00tdqyd574ev2s4q', 'dun', 'Dun', 'Ultimate', 'Unruly Blade', 'Tosses his chain blade in the target location, stunning and dealing damageto enemies hit.When max range is reached or an enemy is hit, the chain blade will pullXiahou Dun to its location, dealing damage to nearby enemies', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc5400u2qyd5botyremn', 'dyadia', 'Dyadia', 'Passive', 'Melodic Swing', 'Enhances her next Basic Attack periodically to swing toward the enemy, dealing damage and knocking them back, then jumping back. When any hero receives Blessing of Fate or Bitter Reconciliation, she earns Gold and reduces the preparation time of her enhanced Basic Attack.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc5500u4qyd5tsmdsik5', 'dyadia', 'Dyadia', '1', 'Heartlink', 'Blesses a teammate and restores Health. When two blessed teammates come close, they recover Health and gain Movement Speed. If she blesses an already blessed teammate, she will dash to them, and both recover Health and gain Movement Speed. Can use this skill again within 5s.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc5500u6qyd55m0f525g', 'dyadia', 'Dyadia', '2', 'Bitter Farewell', 'Marks an enemy, exposes them and deals continuous damage. When two marked enemies come close, they stop taking damage. If she uses the skill on a marked enemy, she will dash to them, immobilizing them and dealing continuous damage. Can use this skill again within 5s.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc5600u8qyd51rsh6re4', 'dyadia', 'Dyadia', 'Ultimate', 'Destined Encounter', 'Commands a swarm of wisps to fly forward, blessing and granting Health recovery to teammates, while marking and damaging enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc5f00uzqyd52mzyu50r', 'erin', 'Erin', 'Passive', 'Elf Dance', 'Her Basic Attack grants Energy. At max Energy, she speeds up, gains a stack of Laurel, and enhances her next Basic Attack. The speed-up increases with her Magical Attack. Her Pierce and Lifesteal stats are linked, using whichever is higher.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc5f00v1qyd5qr4xc2tt', 'erin', 'Erin', '1', 'Dance - Leaf Greeting', 'Shoots a leaf to deal damage and gain marks. The leaf then forms a circle, damaging and slowing enemies. Magical Attack reduces the skill''s cooldown.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc5g00v3qyd5ga4fwelq', 'erin', 'Erin', '2', 'Twirl - Forest Whisper', 'Recovers full Energy and gains marks, immunity to slow, and Attack Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc5g00v5qyd5byinwivc', 'erin', 'Erin', 'Ultimate', 'Waltz - Laurel Bloom', 'This skill is unlocked when Erin gains enough Laurels. She consumes Laurels to deal damage and gain Movement Speed, while reducing the cooldown of Skill 2.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc5o00vuqyd5ypwp4y40', 'fang', 'Fang', 'Passive', 'Going Undercover', 'Periodically reveals a random enemy hero within range.Attacks on monsters deal extra true damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc5x00vwqyd55wql60aq', 'fang', 'Fang', '1', 'Target Sighted', 'Marks the target enemy while gaining attack speed and range. Attacks on marked targets stack more marks, increasing mark damage. When marks expire or reach max stacks, they explode, dealing area damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc5y00vyqyd5akyx82jw', 'fang', 'Fang', '2', 'Wheel Away', 'Dashes in the target direction, slowing and dealing damage to enemies in his path. He is untargetable while dashing. Scorches the ground along the way, slowing and dealing damage to enemies in range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc5y00w0qyd5g6rq1kuk', 'fang', 'Fang', 'Ultimate', 'Bladestorm', 'Throws his blade to the target location,dealing damage over time and slowing enemies wihin range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6700wpqyd5ri6tef9k', 'feyd', 'Feyd', 'Passive', 'Jade Carriage - View from Above', 'Can jump onto and walk on natural walls while gaining Movement Speed. Basic Attack becomes ranged while on a wall.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6700wrqyd5onfw82n0', 'feyd', 'Feyd', '1', 'Jade Chase - Returning Strike', 'Dashes, dealing damage to enemies in his path and launching them. Enhances his next 2 Basic Attacks. Enhanced Basic Attacks deal extra damage and restore Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6800wtqyd5kjz9x1hh', 'feyd', 'Feyd', '2', 'Stepping on Jade', 'Jumps onto the target wall.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6800wvqyd5y4kr5yz4', 'feyd', 'Feyd', 'Ultimate', 'Hardened Jade Seal', 'Deals damage and marks nearby enemies. Using the skill again unleashes 4 strikes of damage and restores his Health. If a marked enemy''s Health is below a certain threshold, the last strike deals grievous damage. When on a wall, he can use this skill to jump down.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6j00xmqyd5ybkcn5rm', 'flowborn-marksman', 'Flowborn (Marksman)', 'Passive', 'Flow of the World', 'Channels the Flow into the body to gain Attack Speed and enhance one of four stats: Health/Attack/Movement Speed/Cooldown.
Can spend Flow to perform an enhanced Basic Attack that deals piercing physical damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6j00xoqyd5bv429jjo', 'flowborn-marksman', 'Flowborn (Marksman)', '1', 'Convergence', 'Deals physical damage to nearby enemies and knocks them back. Gains Health recovery, 5 stacks of Flow, and reduces the cooldown of Arrow of No Retreat and Arrowstorm.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6k00xqqyd5h4zkveot', 'flowborn-marksman', 'Flowborn (Marksman)', '2', 'Arrow of No Retreat', 'Shoots an enormous projectile at the target, dealing physical damage and knocking back non-hero units. Can dash a short distance after use.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6k00xsqyd56fy9upkb', 'flowborn-marksman', 'Flowborn (Marksman)', 'Ultimate', 'Arrowstorm', 'Shoots multiple light projectiles at the target area, dealing physical damage and gaining Movement Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6t00yhqyd5jmvm5ndm', 'fuzi', 'Fuzi', 'Passive', 'Ancient Wisdom', 'After landing 5 Basic Attacks, he becomes enhanced. While enhanced, he gains Attack Speed and Movement Speed. Each Basic Attack deals extra true damage and reduces the cooldown of Skill 1 and Skill 2.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6t00yjqyd5qit1v2om', 'fuzi', 'Fuzi', '1', 'Corporal Punishment', 'Swings his ferule in the target direction, pulling enemies in its path to his location while dealing damage and slowing them.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6t00ylqyd5k2ihglm2', 'fuzi', 'Fuzi', '2', 'Intuition', 'Enhances himself. While enhanced, he reflects every enemy hero''s 1st Basic Attack and slows them. Passive: Basic Attacks have a chance of turning into 2 consecutive Basic Attacks. Passive: Each basic attack has a 25% chance to strike twice, with the second attack dealing 50% damage and applying on-hit effects.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6u00ynqyd5y6pg6zy0', 'fuzi', 'Fuzi', 'Ultimate', 'Sage''s Might', 'Charges in the target direction, dealing damage to the 1st enemy hero hit and restricting their movement to a fixed area for a while. Restricted targets deal less damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6z00yyqyd50h8dv40a', 'gan-mo', 'Gan & Mo', 'Passive', 'Forever Entwined', 'Basic Attacks deal extra damage.Flying Sword hits apply Sword Energy to targets, and Flying Swords dealextra damage to targets marked with Sword Energy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc6z00z0qyd5hfqx51on', 'gan-mo', 'Gan & Mo', '1', 'Guard Her Grave', 'Launches Splitting Sword and moves backwards, knocking back the enemyand dealing damage while reducing their Magical Defense.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7000z2qyd5vxic5o1i', 'gan-mo', 'Gan & Mo', '2', 'Coupled Blades - Short', 'Launches a Flying Sword, dealing damage to enemies in its path.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7000z4qyd5ihxa0ome', 'gan-mo', 'Gan & Mo', 'Ultimate', 'Coupled Blades - Long', 'Launches a Flying Sword, dealing damage to enemies in its path.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7100z6qyd51un4xn5a', 'gan-mo', 'Gan & Mo', 'Ultimate', 'Freshly Forged', 'Immediately refreshes and enhances Flying SwordPassive: Increases field of vision. Each time a flying sword hits an enemy,the cooldown of Freshly Forged is reduced.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7800zrqyd54vhkuiec', 'gao', 'Gao', 'Passive', 'Guitar Solo', 'For every 3 Basic Attacks or skills Gao uses, his Basic Attack is enhanced,dealing damage on hit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7900ztqyd5u61vcpd1', 'gao', 'Gao', '1', 'Wild Chord', 'Launches musical notes that bounce between enemies, dealing damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7900zvqyd5a622pze7', 'gao', 'Gao', '2', 'String Bender', 'Damages and slows enemies within range. Hits on heroes restore Health, and he gains damage reduction during the dash.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7900zxqyd58qao9cq3', 'gao', 'Gao', 'Ultimate', 'Rock Out!', 'Gains Movement Speed and damage reduction while dealing continuous damage to enemies within range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7e0106qyd5i681dak0', 'gao-changgong', 'Gao Changgong', 'Passive', 'Secret Skill - Rush', 'When an enemy is within a certain range from Prince of Lanling, moving toward them will grant him increased Movement Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7e0108qyd5mrm0torm', 'gao-changgong', 'Gao Changgong', '1', 'Secret Skill - Split', 'Deals damage to enemies within a certain range, and deals a 2nd strike of damage to a random enemy in range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7e010aqyd5b9k5pq07', 'gao-changgong', 'Gao Changgong', '2', 'Secret Skill - Sling', 'Throws a dagger that damages, slows, and marks the first enemy in its path. When attacking marked targets, stuns them and recovers Health. Marks deal grievous damage when disappearing.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7f010cqyd5rl278p8y', 'gao-changgong', 'Gao Changgong', 'Ultimate', 'Secret Skill - Strike', 'Exits stealth mode and dashes in the target direction, dealing damage to enemies in his path.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7f010eqyd5nqh3ehw2', 'gao-changgong', 'Gao Changgong', 'Ultimate', 'Secret Skill - Shadow', 'Gao Changgong enters stealth and gains increased movement speed. His next basic attack after exiting stealth deals bonus physical damage and slows the target.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7l010rqyd5r5u7zqo2', 'garo', 'Garo', 'Passive', 'Piercing Arrow', 'Deals double damage to shields with Basic Attacks and skills.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7l010tqyd5ipa394mr', 'garo', 'Garo', '1', 'Enchanted Arrows', ';On: Range and Basic Attack interval increase. Basic Attack costs Mana and deals damage over time. ;Off: Gains Movement Speed and restores range and Basic Attack interval toinitial values.Basic Attack hits restore Mana.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7m010vqyd53vo1o95m', 'garo', 'Garo', '2', 'Silent Arrow', 'Fires an arrow in the target direction, dealing damage to enemies hit while silencing and slowing them. After a brief delay, deals another strike of damage to enemies within range of the same location.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7m010xqyd5h4lzggux', 'garo', 'Garo', 'Ultimate', 'Sphere of Purity', 'Damages enemies in range. Gains Attack Speed and Critical Rate when in the magic circle.Use this skill again to grant Critical Rate and Move Speed to teammates in the circle and damage enemies in the circle', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7u011mqyd5q36u5afx', 'guan-yu', 'Guan Yu', 'Passive', 'Rider of Triumph', '''''''Normal Stance:'''''' Moving constantly accumulates a Movement Speed bonus, and reaching a certain distance activates the Charge Stance. ''''''Charge Stance:'''''' Enhances the next skill and Basic Attack.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7v011oqyd5j8mqnwc6', 'guan-yu', 'Guan Yu', '1', 'Heroic Charge', '''''''Normal Stance:'''''' Deals damage to enemies within range. ''''''Charge Stance:'''''' Charges forward, knocking back enemies in his path while dealing damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7v011qqyd561y1gra5', 'guan-yu', 'Guan Yu', '2', 'Soaring Green Dragon', '''''''Normal Stance:'''''' Removes crowd control effects and gains Movement Speed. ''''''Charge Stance:'''''' Removes crowd control effects and leaps forward, knocking back enemies within the landing area and dealing damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc7w011sqyd5zw80mb6o', 'guan-yu', 'Guan Yu', 'Ultimate', 'Razor Cavalry', '''''''Normal Stance:'''''' Enhances himself, reducing the movement distance required to enter Charge stance. ''''''Charge Stance:'''''' Summons heavy cavalry that dash forward, dealing damage and knocking back enemies in their path.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc85012hqyd5r8s8zcfw', 'guiguzi', 'Guiguzi', 'Passive', 'The Laws of Nature', 'Slips out of vision and enhances the next Basic Attack to inflict extra damage and slow.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc85012jqyd5oxajhufj', 'guiguzi', 'Guiguzi', '1', 'Prophecy - Hidden Hand', 'Gains a Movement Speed boost and a disguise, reducing the Physical andMagical Defense of enemies touched and dealing damage to them.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc86012lqyd5b5f5p6li', 'guiguzi', 'Guiguzi', '2', 'The Animist', 'Summons sprites, and after a brief delay, pulls nearby enemies, inflicting damage and stun. When an enemy hero is hit, gains a shield and grants ashield to all nearby allies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc86012nqyd51torv2s7', 'guiguzi', 'Guiguzi', 'Ultimate', 'Prophecy - Out of Sight', 'After 1s, he grants disguise and Move Speed to himself and near by teammates. Gains vision of the nearest enemy hero. Disguise breaks upon using Basic Attacks, skills, or actions that affect enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc8c0132qyd5sm1lp1dc', 'han-xin', 'Han Xin', 'Passive', 'Killing Spear', 'Han Xin''s every 4th Basic Attack launches the target. Hits from skills andenhanced Basic Attacks grant increased Attack Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc8c0134qyd5o20x7848', 'han-xin', 'Han Xin', '1', 'Ruthless Assault', 'Charges to the target location to deal damage and launch the enemy. The 2nd charge will not launch the enemy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc8d0136qyd5jo3mqm0i', 'han-xin', 'Han Xin', '2', 'Fight or Die!', 'Shifts backward and enhances the next Basic Attack, causing it to deal extra damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc8e0138qyd5wdhquiuy', 'han-xin', 'Han Xin', 'Ultimate', 'The Unrivaled Spear', 'Swings spear 4 times, gaining immunity to damage and crowd control. Deals damage each time and launches enemies the 4th time.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc8m013xqyd5t8sduwdk', 'haya', 'Haya', 'Passive', 'Moon''s Farewell', 'MarkEnhance Spends moon crystals to use skills. When all moon crystals have been spent, her Skill 1 and Skill 2 will enter their (full) cooldowns, and her next Basic Attack is enhanced, dealing extra damage. Skill 1 and Skill 2 apply a mark on hit. Hitting marked targets again triggers additional effects.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc8m013zqyd53ep8dhwb', 'haya', 'Haya', '1', 'Crescent Wave', 'Damage Unleashes a beam of moonlight, dealing damage. Deals extra damage if a mark is triggered.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc8m0141qyd5uzfx292u', 'haya', 'Haya', '2', 'Wayward Rays', 'ShieldCrowd Control Releases orbs to deal damage while gaining a shield and increased Movement Speed. If mark are triggered, targets will be stunned.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc8n0143qyd57vgaif2o', 'haya', 'Haya', 'Ultimate', 'Moonscape Mirage', 'DreamscapeCooldownShield Links to a hero, gaining damage reduction while linked. After a delay, they enter a mirage. Upon entering, she gains a shield, and her skill cooldowns are shorter. If she uses this skill again while inside the mirage, she moves 700 units away from the target.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc8w014sqyd5k70xze1q', 'heino', 'Heino', 'Passive', 'Fate''s Guidance', 'Heino''s Basic Attacks differ depending on whether he''s in melee or ranged mode. Basic Attacks deal physical and magical damage, and melee Basic Attacks and skills place marks on hit enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc8w014uqyd5lxqlh5q6', 'heino', 'Heino', '1', 'Scepter of Fate', 'Reduces cooldown by 0.2s for each marked enemy hit, up to 1s. ;Ranged: Throws scepter to deal magical damage and again to marked targets forward. ;Melee: Throws scepter to damage and slow enemies. Recovers Health on hitting marked enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc8x014wqyd58z4uccph', 'heino', 'Heino', '2', 'Leap of Fate', 'Dashes forward. lf there are enemy heroes near the end of the dash, goesinto melee mode, recovers Health, and increases Max Health, Physical Defense and Magical Defense. Otherwise, goes into ranged mode and gains Movement Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc8x014yqyd5s7smzp8a', 'heino', 'Heino', 'Ultimate', 'Fate Rewind', 'Heino gains damage reduction and crowd control immunity, recovers Health, but cannot move. After 1.5s, he deals magical damage and travels back in time. The allied tower within range travels 5s back in time. He recovers more Health the less he has left.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc96015nqyd5ykbtcln7', 'hou-yi', 'Hou Yi', 'Passive', 'Chastising Shot', 'Basic Attack hits grant Attack Speed and 1 stack of enhancement.At 3 stacks, enhanced Basic Attacks shoot 3 arrows, dealing more totaldamage than a regular Basic Attack.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc96015pqyd54v2c3w0v', 'hou-yi', 'Hou Yi', '1', 'Arrow Volley', 'Enhances Basic Attacks for 5s to deal heavy damage. At the same time, HouYi shoots arrows to hit two other enemies in front of him, dealing 50%damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc97015rqyd5gv1waavt', 'hou-yi', 'Hou Yi', '2', 'Afterglow', 'Inflicts damage and slow on enemies in the target area while also gaining vision of the area.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc97015tqyd5s7g7m819', 'hou-yi', 'Hou Yi', 'Ultimate', 'Burning Sun Arrow', 'Fires an arrow in the target direction. Deals AoE damage upon hitting a hero inflicting stun and slow.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc9g016iqyd5argokqfj', 'huang-zhong', 'Huang Zhong', 'Passive', 'Gunner''s Spirit', 'Basic Attacks increase attack and Critical Rate', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc9h016kqyd5213wg2sf', 'huang-zhong', 'Huang Zhong', '1', 'Unleash Your Potential', 'Gains Movement Speed and permanently increased attack. Cast while in Cannon form to immediately exit the state.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc9h016mqyd5fg0ai7qo', 'huang-zhong', 'Huang Zhong', '2', 'Lay the Mines', 'Places a trap in the target area. The trap grants vision of enemies that touchit, while also inflicting damage, slow, and Sunder on them and granting Huang Zhong a shield.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc9i016oqyd5ek93qh6z', 'huang-zhong', 'Huang Zhong', 'Ultimate', 'Bring out the Artillery', 'Huang Zhong dashes for a certain distance and deploys a turret while refreshing his Skill 1. He becomes immobile, gains range and Physical and Magical Defense Basic Attacks deal area damage.The turret will be deactivated after a certain number of Basic Attacks.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc9q0179qyd5ejwgseu7', 'jing', 'Jing', 'Passive', 'Lethal Reflections', 'Jing and her image apply 2 different types of marks on enemies when they deal damage. If an enemy has both types of mark at the same time, they take damage and the cooldowns of Skill 1 and Skill 2 are reset.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc9r017bqyd5t2zy094u', 'jing', 'Jing', '1', 'Reflective Assault', 'Dashes forward, damaging enemies in her path and slowing them while enhancing her next Basic Attack.
If no mirror image is present on the battlefield, one will be created to fight alongside her.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc9r017dqyd5cg1d4evo', 'jing', 'Jing', '2', 'Shattered Illusions', 'Deals damage to nearby enemies while recovering Health and gaining increased Movement Speed.
If no mirror image is present on the battlefield, then one will be created to fight alongside her.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzc9s017fqyd5q16njldm', 'jing', 'Jing', 'Ultimate', 'Mirror Domain', 'Dashes forward, pulling enemies to the center of her magic circle and immobilizing them there. She gains damage reduction while inside the circle, and recovers Health when she swaps locations.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzca20184qyd5jla1agjs', 'kaizer', 'Kaizer', 'Passive', 'Demon Soul', 'Basic Attacks and Skill 2 deal extra damage to single targets', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzca20186qyd5j0vf3bkp', 'kaizer', 'Kaizer', '1', 'Vortex Brand', 'Throws a ricocheting blade in the target direction, damaging and slowing enemies hit. The blade returns on hit, restoring Health and granting Move and Attack Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzca30188qyd54rfap0cc', 'kaizer', 'Kaizer', '2', 'Blade Tempest', 'Slashes twice, dealing damage. The second slash launches enemies and increases the damage of the next Basic Attack. Gains increased Health recovery, Mana recovery, and Movement Speed when out of combat.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzca3018aqyd5rwcdijyq', 'kaizer', 'Kaizer', 'Ultimate', 'Invincible Warrior', 'Becomes enhanced, gaining Movement Speed, max Health, Physical AttackBlock, and damaging nearby enemies over time.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcac018zqyd56n6zl487', 'kongming', 'Kongming', 'Passive', 'Time for Tactics', 'Active skill hits on enemies grant 1 stack. At the max of 5 stacks, he summons prisms to attack nearby enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcac0191qyd5qhzipg21', 'kongming', 'Kongming', '1', 'Arcane Assault', 'Fires 3 orbs in a fan-shaped area, dealing damage to enemies hit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcac0193qyd565mi21cj', 'kongming', 'Kongming', '2', 'Time Shift', 'Shifts in the target direction, dealing damage to enemies near the start and end points.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcad0195qyd554lwu4l2', 'kongming', 'Kongming', 'Ultimate', 'Winning Strategy', 'Channels briefly and unleashes a spirit bomb at the target enemy, dealing lethal damage. lf the bomb defeats an enemy hero, the skill''s cooldown is refreshed', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcak019qqyd5yl0pg1gy', 'kui', 'Kui', 'Passive', 'Ethereal Outburst', 'Deals area damage upon taking heavy damage in a single hit or after dying.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcak019sqyd51rf6f0fw', 'kui', 'Kui', '1', 'Mortals!', 'Inflicts damage and slow on enemies in the target area.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcal019uqyd5c880hnda', 'kui', 'Kui', '2', 'Join Me', 'Throws his chain hook in the target direction, damaging the enemy and pulling them to him. Upon learning this skill, gains a passive effect that increases his Health on defeats and assists.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcam019wqyd53422dp6z', 'kui', 'Kui', 'Ultimate', 'Into the Void', 'Deals damage multiple times and slows enemies within range. For heroes marked by Skill 2, the slow effect is upgraded to a stun.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcaq01a5qyd5vx4zgt1j', 'lady-sun', 'Lady Sun', 'Passive', 'Energy Burst', 'Basic Attacks reduce the cooldown of Skill 1.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcaq01a7qyd5cboxe0d5', 'lady-sun', 'Lady Sun', '1', 'Rolling Raid', 'Rolls in the target direction, granting extra range and a piercing effect to the next Basic Attack. Gains increased Movement Speed if there are enemy heroes nearby after rolling.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcar01a9qyd5rldh4o7g', 'lady-sun', 'Lady Sun', '2', 'Frag Grenade', 'Throws a grenade at the target location, damaging, marking, and sundering hit enemies. Her Basic Attack deals extra damage to marked targets.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcar01abqyd5ak5w12ne', 'lady-sun', 'Lady Sun', 'Ultimate', 'Ultimate Shell', 'Fires a shell in the target direction, dealing AoE damage when enemies are hit or when exploding at max range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcaz01b0qyd5dxdxevtk', 'lady-zhen', 'Lady Zhen', 'Passive', 'Frozen Touch', 'Places marks on enemies when hitting them with skills, for up to 3 stacks. Upon reaching max stacks, she freezes and damages the enemy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcaz01b2qyd5vxo3uv8t', 'lady-zhen', 'Lady Zhen', '1', 'Ocean of Tears', 'Damages and launches enemies within the target area', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcaz01b4qyd5usoizvmw', 'lady-zhen', 'Lady Zhen', '2', 'Flowing Sigh', 'Fires a water orb at the target, which deals damage and bounces between nearby enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcb001b6qyd5gx6tshh0', 'lady-zhen', 'Lady Zhen', 'Ultimate', 'Destructive Deluge', 'Fires a stream of water in the target direction. For a period of time after hitting an enemy hero or reaching its maximum range, the stream of water reforms into a pool, dealing damage and slowing enemies within it.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcb601bpqyd5ikmy7yxh', 'lam', 'Lam', 'Passive', 'Hunter', 'Basic Attacks and skills deal extra true damage to targets with low Health', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcb701brqyd5d4nt8g19', 'lam', 'Lam', '1', 'Wavebreaker', 'Lam enters “Submerged” state, greatly increasing his Movement Speed for 3 seconds. When the duration ends, Lam leaps out of the water, immediately restoring 50% of this skill’s cooldown. While in Submerged state, casting the skill again will cause Lam to surface early, dealing 300 (+120% Bonus Physical Attack) Physical Damage to nearby enemies and slowing their Movement Speed by 50% for 1.5 seconds. Passive: While in river terrain, the Submerged state has no time limit. If an enemy hero with below 30% Health appears within 1500 range, Lam gains 450 Movement Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcb701btqyd5x8nb8d7x', 'lam', 'Lam', '2', 'Space Split', 'Damages nearby enemies while gaining a mark. Basic Attacks spend marks to gain a dash and Health recovery effect. While submerged, Skill 2 has an extra dash effect.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcb701bvqyd589h9i1r5', 'lam', 'Lam', 'Ultimate', 'Death From Below', 'Throws a dagger in the target direction, then dashes to the dagger after a short delay, dragging enemies in his path to the dagger and dealing damage to them. Submerged: Cancels the cast animation and skill delay.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcbf01ckqyd5z9ylqm04', 'li-bai', 'Li Bai', 'Passive', 'Way of the Sword', 'Basic Attack hits grant stacks. At 4 stacks, increases Physical Attack and unlocks the Ultimate.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcbf01cmqyd5vi7fzi5v', 'li-bai', 'Li Bai', '1', 'Stupor Slash', 'Dashes and leaves an after image at the start point while stunning and damaging enemies in his path.Can dash again before cooldown starts, and a third time to return to the after image.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcbg01coqyd5vk83rulh', 'li-bai', 'Li Bai', '2', 'Stroke of Genius', 'Removes crowd control effects from self and becomes untargetable. Damages enemies in range, leaving behind a sword formation. Enemies that touch the edge of the formation are damaged, slowed, andsundered.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcbg01cqqyd5f4v443c5', 'li-bai', 'Li Bai', 'Ultimate', 'Flickering Flurry', 'Transforms into a phantom, continuously slashing at the specified area. Li Bai is untargetable while the skill is active, and all debuffs are removed Deals AoE damage, but damage is diminished upon hitting multiple enemy heroes.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcbo01dfqyd53ki5ihuo', 'li-xin', 'Li Xin', 'Passive', 'Ashen Razor', 'Gains EXP when hitting enemy heroes with Basic Attacks and Chaos Wave.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcbp01dhqyd5lyy5tc3d', 'li-xin', 'Li Xin', 'Ultimate', 'Dark Awakening', 'Transforms into Revenge form. This process cannot be interrupted and is faster at higher skill levels.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcbp01djqyd5qortv3rn', 'li-xin', 'Li Xin', 'Passive', 'Void Slice', 'Gains Movement Speed and deals an extra instance of damage after each Basic Attack.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcbq01dlqyd598hg18ya', 'li-xin', 'Li Xin', 'Ultimate', 'Force Mastery', 'Transforms into Domination Form and deals damage to nearby enemies. This process cannot be interrupted.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcbq01dnqyd59i5c8pjw', 'li-xin', 'Li Xin', 'Passive', 'Scorched Strikes', 'After using a skill, enhances the next Basic Attack with increased range, a pierce effect, and extra damage. Hitting a target reduces all skill cooldowns.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcbr01dpqyd5qwtmt59g', 'li-xin', 'Li Xin', 'Ultimate', 'Force Break', 'Transforms into Revenge Form and deals damage to nearby enemies. This process cannot be interrupted.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcbz01eeqyd5yq2b8m3u', 'lian-po', 'Lian Po', 'Passive', 'Warrior''s Soul', 'Gains immunity while using skills. Gains Battle Spirit upon entering combat, using Basic Attacks or skills. Battle Spirit increases damage reduction. Attack Speed increases at max Battle Spirit. When out of combat, Battle Spirit will diminish while restoring Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcbz01egqyd5kkr4ime5', 'lian-po', 'Lian Po', '1', 'Burst Ram', 'Charges in the target direction, dealing damage and launching enemies in the path. Passive: Every 2 Basic Attacks, enhances the next Basic Attack to deal extra damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcc001eiqyd55y21lvck', 'lian-po', 'Lian Po', '2', 'Magma Slam', 'Gains a shield.Slows nearby enemies a certain range.After a brief delay, deals damage to enemies in range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcc001ekqyd58vr1aaet', 'lian-po', 'Lian Po', 'Ultimate', 'Tremor Smash', 'Leaps to the target location and hammers the ground 3 times. The first 2blows deal damage and slow enemies, while the 3rd blow deals damage and launches enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcc701f7qyd58xoi7xgb', 'liang', 'Liang', 'Passive', 'Power Word - Trance', 'Every second hit on the same target within a short time will deal an extra strike of damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcc801f9qyd5gsuuk625', 'liang', 'Liang', '1', 'Power Word - Barrier', 'Summons 4 barriers that shatter when touched by an enemy, inflicting damage, stun, and slow. Damage and slowing effects are reduced for enemies that touch multiple barriers.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcc801fbqyd54ewyig99', 'liang', 'Liang', '2', 'Power Word - Fate', 'Summons a magic circle that deals damage to enemies within range while granting vision of the area. Liang gains Movement Speed while inside his magic circle.', '[]', '[]', NULL, NULL, '', '');
