INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzccf01fsqyd55y5978ym', 'liu-bang', 'Liu Bang', 'Passive', 'Royal Ambition', 'Gains 1 mark every second, for up to 4 marks. Basic Attacks expend all marks, dealing additional magical damage per mark. At maximum marks, the next Basic Attack is enhanced into a ranged attack.', '[]', '[]', NULL, NULL, '', '');
