INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzccf01fwqyd52sllncu6', 'liu-bang', 'Liu Bang', '2', 'Staggering Charge', 'Charges up and dashes forward, damaging and stunning enemies in his path.', '[]', '[]', NULL, NULL, '', '');
