INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzccm01gbqyd59hvd5w4y', 'liu-bei', 'Liu Bei', 'Passive', 'Reinforced Shells', 'When Basic Attacks hit a hero, it increases his Physical Pierce.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzccm01gdqyd5oj7yh8dd', 'liu-bei', 'Liu Bei', '1', 'Dual Shot', 'Increases Movement Speed and enhances the next Basic Attack to damage twice.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzccm01gfqyd5k6dcglaw', 'liu-bei', 'Liu Bei', '2', 'Leading the Charge', 'Dashes forward, damaging and knocking back enemies in the way.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzccn01ghqyd5qyezqmtx', 'liu-bei', 'Liu Bei', 'Ultimate', 'Hearts and Minds', 'Removes crowd control, increases Physical Attack, and gains crowd control immunity and a shield.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzccv01h4qyd5b4zwyhce', 'liu-shan', 'Liu Shan', 'Passive', 'Magnetic Barrier', 'Liu Shan''s skills deal equal damage to structures and can disrupt them while also recovering Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzccv01h6qyd51prjl3qv', 'liu-shan', 'Liu Shan', '1', 'Overcharge!', 'Gains a shield and increased Movement Speed while enhancing the next Basic Attack, dealing damage, and launching the target.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzccw01h8qyd54nh0xtbq', 'liu-shan', 'Liu Shan', '2', 'Robo Smash', 'Inflicts damage and stun on enemies in the target area.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzccw01haqyd52s2oxseg', 'liu-shan', 'Liu Shan', 'Ultimate', 'Take It for a Spin', 'Launches a spinning attack that continuously deals damage to nearby enemies. While spinning, Basic Attacks slow and deal damage to targets.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcd101hlqyd5ki12k5cj', 'lu-bu', 'Lu Bu', 'Passive', 'Bloodthirsty Ancestry', 'Becomes enhanced when Skill 1 or Ultimate hits an enemy hero. While enhanced, Basic Attacks, Skill 1, and Ultimate deal true damage and restore Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcd101hnqyd5oom8syn7', 'lu-bu', 'Lu Bu', '1', 'Impaling Thrust', 'Performs a sweep attack to the target area. Restores a certain amount of Health with each enemy hero hit. Failing to hit a hero will cause the enhancement to disappear.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcd101hpqyd5rwluao53', 'lu-bu', 'Lu Bu', '2', 'Souleater', 'Slows enemies in the target area and grants a shield for each enemy hit (upto 3 stacks). The shield value is converted to Health over time.', '[]', '[]', NULL, NULL, '', '');
