INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcd901ieqyd5d4ippzqy', 'luban-no-7', 'Luban No.7', 'Passive', 'Suppressive Fire', 'Every 5 Basic Attacks or the first Basic Attack after using a skill gains a piercing effect and deals continuous damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcda01igqyd5gyrjwkjx', 'luban-no-7', 'Luban No.7', '1', 'Blowfish Grenade', 'Throws a bomb at the target area, dealing damage and slowing all enemies hit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcda01iiqyd56wesbibh', 'luban-no-7', 'Luban No.7', '2', 'Shark Cannon', 'Launches a rocket in the target direction, knocking back enemies in close range and dealing damage. Deals damage to enemies in range upon exploding on enemy heroes.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcdb01ikqyd5uco8b5tz', 'luban-no-7', 'Luban No.7', 'Ultimate', 'Air Support', 'Bombards the target location, slowing and dealing damage to enemies while gaining vision of the area.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcdf01itqyd5ydfvpxee', 'luna', 'Luna', 'Passive', 'Moonlight Dance', 'Every three Basic Attacks form a repeating cycle. On the first, she dashes toward the target, and on the third, she deals damage to nearby enemies and places a mark on them. Increasing Magical Attack also increases Attack Speed', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcdg01ivqyd5jbzdnhht', 'luna', 'Luna', '1', 'Crescent Slice', 'Unleashes a shockwave in the target direction, dealing damage and marking enemies hit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcdg01ixqyd58ssyk1ah', 'luna', 'Luna', '2', 'Searing Stab', 'Gains a shield and pulls nearby enemies, dealing damage while stunning slowing, and marking them.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcdg01izqyd5qnfxlzsn', 'luna', 'Luna', 'Ultimate', 'New Moon', 'Dashes in the target direction, dealing damage to enemies in her path. Upon hitting marked enemies, her Ultimate''s cooldown will be refreshed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcdo01joqyd5304srbxq', 'mai-shiranui', 'Mai Shiranui', 'Passive', 'HISSATSU SHINOBI-BACHI', 'Periodically gains an enhanced Basic Attack that lets her dash while dealing damage and knocking back enemies in her path. After using an enhanced Basic Attack or any skill, she can roll and gain Movement Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcdo01jqqyd5fyxe4mgf', 'mai-shiranui', 'Mai Shiranui', '1', 'HISHOU RYUUENJIN', 'Dashes forward to deal damage and launch enemies in the target area. Recovers Energy upon hit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcdp01jsqyd5irdmlzdm', 'mai-shiranui', 'Mai Shiranui', '2', 'KACHOUSEN', 'Throws her fan to damage and slow a target enemy while reducing their Magical Defense. Hits recover Energy. After it hits, the fan also deals magical damage to the closest unit behind the target.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcdp01juqyd5i5wv71ir', 'mai-shiranui', 'Mai Shiranui', 'Ultimate', 'CHOU HISSATSU SHINOBI-BACHI', 'Dashes forward to deal damage and knock back enemies while reducing their Physical Attack. Recovers Energy upon hitting a target.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcdx01kjqyd5kso2jne3', 'marco-polo', 'Marco Polo', 'Passive', 'Chain Reaction', 'Basic Attack and skill hits inflict stacks on the opponent, dealing extra truedamage at max stacks. Extra Attack Speed bonuses increase the number ofbullets fired by Skill 1 and 3.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcdx01klqyd52fu8398u', 'marco-polo', 'Marco Polo', '1', 'Resplendent Revolver', 'Fires in the target direction for a period of time and gains increasedMovement Speed while firing.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcdy01knqyd5eble7gi6', 'marco-polo', 'Marco Polo', '2', 'Roaming Gun', 'Teleports in the target direction.Passive: Gains Attack and Movement Speed when a nearby enemy hero is within range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcdy01kpqyd50zlxnh9e', 'marco-polo', 'Marco Polo', 'Ultimate', 'Fevered Barrage', 'Shifts in the target direction and deals damage over time to nearby enemies within range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzce601leqyd5tvz2prfw', 'mayene', 'Mayene', 'Passive', 'Slack Off a Lil Bit', 'Recovery replaced by Slack Off, which restores Strength and Health. She will also slack off while at rest.She will not slack off when she attacks, is attacked, moves, or is in the Serious State.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzce601lgqyd5jvctuijn', 'mayene', 'Mayene', '1', 'Whatever (I)', 'Costs 1 Punch Strength. Runs forward, pulling in enemies in a cone-shaped area and damaging them.F ollow up with Skill 2 or another use of this skill for various effects.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzce701liqyd59e989int', 'mayene', 'Mayene', '2', 'Whatever (II)', 'Costs 1 Kick Strength. Jumps to dodge crowd controls and damage, and recover Health. Can follow up with Skill 2 or another use of this skill for different effects.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzce701lkqyd5uxp37u1b', 'mayene', 'Mayene', 'Ultimate', 'Get Serious', 'Damages nearby enemies. Recovers 1 Punch Strength and Kick Strength Bar, and increases max Strength for each by 1. Gains Movement Speed and is less affected by slow.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzce701lmqyd5bgqhary9', 'mayene', 'Mayene', 'Ultimate', 'Exploit Weakness', 'Combo when using after Skill 1. Costs 1 Punch Strength. Jumps and delivers a powerful strike, damaging nearby enemies. Enemies at the center take more damage, Gains damage reduction while using the skill.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzce801loqyd59pn13hfy', 'mayene', 'Mayene', 'Ultimate', 'Feint to Retreat', 'When Whatever (II) is used quickly after Whatever (I), Mayene will deliver afluid combo of strikes, dealing physical damage to the target while pushing them backward slightly (without crowd control effects) and recovering Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzce801lqqyd5c5mjqsp9', 'mayene', 'Mayene', 'Ultimate', 'Defend by Attacking', 'When Whatever (I) is used quickly after Whatever (II), Mayene will deliver a powerful strike. She teleports behind the enemy and launches a spinning kick, knocking back the target and dealing physical damage. lf the target is defeated, she recovers some Health and Strength.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzce801lsqyd5sjbbqmb1', 'mayene', 'Mayene', 'Ultimate', 'Flee Danger', 'Combo when using after Skill 2. Costs 1 Kick Strength Jumps at the enemy, then flips in the target direction, damaging the enemy and recovering Health. Untargetable and recovers Health while using.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzceg01mjqyd5b56xqoyb', 'meng-ya', 'Meng Ya', 'Passive', 'Fiery Temper', 'Cooldown is reduced when Attack Speed is increased. Gains Anger when Basic Attack and Skill 1 hit targets. At max Anger, becomes Excited, enhancing all skills. While Excited, surplus Anger restores Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzceg01mlqyd5sqsmdmye', 'meng-ya', 'Meng Ya', '1', 'Awesome Barrage', 'Uses the Apocalyptor to strafe continuously and deal damage. ''''''Excited:'''''' Bullets have a piercing effect, dealing half damage to subsequent enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzceh01mnqyd56b9kl9om', 'meng-ya', 'Meng Ya', '2', 'Heavy Shot', 'Shoots a heavy round in the target direction, inflicting damage and slow. Upon hitting an obstacle or reaching its max range, it will split into splinters that deal damage. ''''''Excited:'''''' Increases the number of splinters.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzceh01mpqyd5437ewx91', 'meng-ya', 'Meng Ya', 'Ultimate', 'Missile Mayhem', 'Scans the vicinity and fires missiles at enemies within range who are attacked by teammates, dealing damage. ''''''Excited:'''''' Reduces interval between missiles.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzceq01neqyd5c9uvu7hn', 'menki', 'Menki', 'Passive', 'Dream-eating', 'Gains Mass when using skills. Mass increases his Physical Attack, Physical Defense, and Magical Defense.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzceq01ngqyd57as8cpzm', 'menki', 'Menki', '1', 'Lingering Dream', 'Gains Mass and a shield while damaging enemies in range. Basic Attack hits reduce this skill''s cooldown.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzceq01niqyd5nxa3b8on', 'menki', 'Menki', '2', 'Dream Bubble', 'Launches a bubble in the target direction, then pulls it back. He does thistwice. The bubble damages and slows enemies hit.The bubble can be launched again as a bomb in the target direction, damaging enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcer01nkqyd5s2rhvetp', 'menki', 'Menki', 'Ultimate', 'Dream Roam', 'Flies in a circle, dealing magical damage to enemies in his path and gaining. Mass all the while. When he stops flying, he launches and damages nearby enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcex01o1qyd5fe351dvp', 'mi-yue', 'Mi Yue', 'Passive', 'Eternal Youth', 'Summons a shadow servant that damages enemies and restores Health to her whenever using a skill. She also gains Shadow Power that boosts her Movement Speed and healing effects.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcex01o3qyd51eycq42j', 'mi-yue', 'Mi Yue', '1', 'Dark Transfer', 'Unleashes shadow energy, dealing damage to enemies that come into contact with it. Upon using the skill again, will shift to the shadow''s location, dealing damage again. A shadow servant will be summoned if she hits an enemy after shifting.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcey01o5qyd58smev3dq', 'mi-yue', 'Mi Yue', '2', 'Ravenous Tether', 'Releases a tether that links to the first enemy hit. Damages and slows over time. Steals Physical and Magical Attack while recovering Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcey01o7qyd5ejlyasnw', 'mi-yue', 'Mi Yue', 'Ultimate', 'Umbral Moon', 'Removes debuffs, gains Movement Speed, and becomes untargetable. Deals damage to nearby enemies upon entering and exiting the untargetable state.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcf501ooqyd5npao8200', 'milady', 'Milady', 'Passive', 'Mechanical Minions', 'Summons minions upon killing a unit. Minions attack automatically, then merge into an advanced bot or explode at the end of their duration, dealing damage to nearby enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcf501oqqyd5lu0vscfa', 'milady', 'Milady', '1', 'Air Superiority', 'Commands her aircraft to move in the target direction, dealing damage to enemies in its path. Using the skill again splits the aircraft in two, dealing damage and inflicting slow.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcf601osqyd5jp7a8sbk', 'milady', 'Milady', '2', 'Forced Invasion', 'Summons mechanical minions in the target area, dealing area damage before automatically attacking nearby enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcf601ouqyd5jyvdnhc2', 'milady', 'Milady', 'Ultimate', 'Chaos Field', 'Marks a target enemy or structure, damaging them over time. Non-structures are also stunned and slowed. Nearby mechanical minions are enhanced while marks are active. Marks explode upon expiry, dealing damage proportional to the damage taken while marked.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfd01pfqyd5tfe8fryh', 'ming', 'Ming', 'Passive', 'Good Omens', 'Every 5s, Ming''s next Basic Attack deals more magical damage and heals himself and the linked teammate. The healing is reduced if the enemy is nota hero.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfd01phqyd5j41rqryw', 'ming', 'Ming', '1', 'Time - Carefree', 'Forms a link with the target. When linked to an ally, increases the Physical and Magical Attack Movement Speed, and Attack Speed of both parties. When linked to an enemy unit, reduces their Physical and Magical Attack while dealing damage over time.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfe01pjqyd5guhvj5bd', 'ming', 'Ming', '2', 'Mastery - Glide', 'Switches the effect of the link. When linked to an ally, increases the Physical and Magical Defense of both parties. When linked to an enemy unit, reduces their Physical and Magical Defense. The effect can beswitched repeatedly.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfe01plqyd5axwny5jo', 'ming', 'Ming', 'Ultimate', 'Peace - Longevity', 'While linked, can spend own Health to restore an equal amount of Health toallies or deal an equal amount of damage to enemies. Recovers Health continuously while out of combat.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfn01q6qyd5fp48oyoc', 'mozi', 'Mozi', 'Passive', 'Fight for Peace', 'Every 4th Basic Attack deals area damage and knocks back enemies. Gains shield stacks when using skills, for up to 3 stacks.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfo01q8qyd5blnzl95e', 'mozi', 'Mozi', '1', 'Peacebringer', 'Dashes in the target direction, dealing damage to enemies along the way. The next Basic Attack is enhanced, becoming Fight for Peace.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfo01qaqyd5s0rj5owh', 'mozi', 'Mozi', '2', 'Cannon Blast', 'Fires a shell in the target direction, stunning and dealing AoE damage to the 1st enemy hit. The shell leaves a crater in the ground after reaching its max range or hitting an enemy, dealing damage over time to enemies that step init.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfp01qcqyd569ep8b69', 'mozi', 'Mozi', 'Ultimate', 'Think Inside the Box', 'Deals continuous damage to enemies within a certain range of himself, stunning enemies every time he deals damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfu01qpqyd5clwemzqm', 'mulan', 'Mulan', 'Passive', 'Great Wall Guardian (Dual Swords Form)', 'Gains Movement Speed when using dual swords. Skills and Basic Attacks apply marks to enemies. At 5 stacks, the marks disappear, dealing damage and inflicting silence and slow on the enemy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfu01qrqyd5ik2lvsc9', 'mulan', 'Mulan', '1', 'Snaking Strike', 'Dashes twice in the target direction, and the direction of the 2nd dash can be controlled. Deals damage to enemies in her path. lf the skill hits an enemy, she can use it again before it enters cooldown.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfv01qtqyd57bbzx7jf', 'mulan', 'Mulan', '2', 'Dagger Waltz', 'Throws a light sword in the target direction, slowing and dealing damage to enemies in range when it reaches max range. When Hua Mulan reaches the light sword, she puts it away, reducing thecooldown of Dagger Waltz.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfv01qvqyd5ff27b2kf', 'mulan', 'Mulan', 'Ultimate', 'Blooming Blade (Dual Swords Form)', 'Deals damage to enemies within range, gaining damage reduction during this time. Enhances herself, gaining Physical Attack during the enhancement. Switches to Heavy Sword Form.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfv01qxqyd5sz08eafi', 'mulan', 'Mulan', 'Ultimate', 'Great Wall Guardian (Heavy Sword Form)', 'Gains Movement Speed when using dual swords. Skills and Basic Attacks apply marks to enemies. At 5 stacks, the marks disappear, dealing damage and inflicting silence and slow on the enemy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfw01qzqyd5cmqqa1zi', 'mulan', 'Mulan', 'Ultimate', 'Sundering Slash', 'Damages and slows enemies in range. Charges up the skill for greater damage, slow, and even launch. This skill can be used again on hit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfw01r1qyd5egq4be1u', 'mulan', 'Mulan', 'Ultimate', 'Blade Flurry (Mulan)', 'Slashes up to 4 times in the specified direction, with each slash slowing knocking back, and dealing damage to any enemies hit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcfx01r3qyd5emyr89vj', 'mulan', 'Mulan', 'Ultimate', 'Blooming Blade (Heavy Blade Form)', 'Deals damage to enemies in range. Enhances herself, gaining Attack Speed while enhanced. Switches to Dual Swords Form.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcg301rkqyd5qdve00lc', 'musashi', 'Musashi', 'Passive', 'Niten Ichiryuu', 'Using skills generates Vigor, which is consumed by Basic Attacks to gain enhancement effects. Hitting an enemy reduces the cooldown of Skills 1 and Skills 2. Vigor can stack up to two times. 1 Vigor: Enhances Basic Attack damage. 2 Vigor: Dashes and slows enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcg401rmqyd5ejhinxd1', 'musashi', 'Musashi', '1', 'Illuminating Slash', 'Unleashes sword energy in the target direction, dealing damage to enemies in its path and knocking down projectiles. Becomes immune to crowd control when using the skill.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcg401roqyd5a6yswkz1', 'musashi', 'Musashi', '2', 'Extreme Speed', 'Dashes in the target direction, dealing damage and gaining a shield upon hitting an enemy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcg501rqqyd5tgi87kpe', 'musashi', 'Musashi', 'Ultimate', 'Duel to the Death', 'Dashes to the target, launching them and dealing damage to enemies within range, while delaying the target''s recovery effects.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcgd01sfqyd5nldfn5pl', 'nakoruru', 'Nakoruru', 'Passive', 'DANCING SWORD ARTS', 'After hitting an enemy with a skill, the next Basic Attack is enhanced, dealing extra damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcge01shqyd5kno2l8yh', 'nakoruru', 'Nakoruru', '1', 'AMUBE YATORO', 'Deals damage to a targeted enemy and marks the target. Her attacks can trigger the mark to deal extra damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcge01sjqyd53uehpscb', 'nakoruru', 'Nakoruru', '2', 'RERA MUTSUBE', 'Dashes in the target direction, dealing damage to enemies in her path. Recovers Health for each enemy hit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcge01slqyd5lwv1hhy9', 'nakoruru', 'Nakoruru', 'Ultimate', 'KAMUI MUTSUBE', 'Gains Movement Speed. Using the skill again deals damage to enemies in the target area, slows them, and reduces their attack.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcgm01taqyd5030x930z', 'nezha', 'Nezha', 'Passive', 'Scorching Ember', 'Gains Movement Speed and a shield that negates true damage when attacking the enemy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcgn01tcqyd55momdxjy', 'nezha', 'Nezha', '1', 'Fire-tipped Spear - Sweep', 'Attacks nearby enemies, dealing damage. This attack also weakens the recovery capability of heroes and deals true damage over time.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcgn01teqyd5ylybphp7', 'nezha', 'Nezha', '2', 'Red Armillary Sash - Bind', 'Flips behind the target to deal damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcgo01tgqyd5hjcstkb2', 'nezha', 'Nezha', 'Ultimate', 'Universe Ring', 'Unleashes the universe ring, dealing damage to enemy heroes across the entire map and gaining vision. Enhances the range of Universe Ring - Skyfall to cover the entire map for 5s.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcgv01u5qyd5o4d1zmjl', 'nuwa', 'Nuwa', 'Passive', 'Divine Consciousness', 'Gains enhanced vision and range when leveling up.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcgw01u7qyd5p4fhftx0', 'nuwa', 'Nuwa', '1', 'Divine Glow - Creation', 'Unleashes energy that deals damage, knocks back enemies, and creates a matrix. When the energy stops, it expands to deal extra damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcgw01u9qyd5dm18hl5k', 'nuwa', 'Nuwa', '2', 'Divine Glow - Coalescence', 'Creates a matrix and allows her to teleport. The matrix blocks enemy heroes'' movement. Matrices can be fused twice.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcgw01ubqyd5sk6zvndm', 'nuwa', 'Nuwa', 'Ultimate', 'Divine Glow - Emergence', 'Teleports to the target area after a short delay. Generates a shield, gains Movement Speed, deals damage, and slows the enemy. Passive: Magical Attack can reduce cast time.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcgx01udqyd57jd3c9o0', 'nuwa', 'Nuwa', 'Ultimate', 'Divine Glow - Annihilation', 'Deals damage to targets ahead.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzch501v2qyd59ocl3470', 'pei', 'Pei', 'Passive', 'Blast', 'In human form, Basic Attacks have increased range and deal extra magical damage while recovering Energy. Consecutive hits on the same target will stack damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzch501v4qyd5u6sb8vcz', 'pei', 'Pei', '1', 'Striker Stance', 'Fires Inner Energy in the target direction, dealing damage to enemies in its path and slowing them. Recovers Energy upon hit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzch501v6qyd5ijdc7yq7', 'pei', 'Pei', '2', 'Guarding Stance', 'Grants shield points and increases Attack SpeedDeals damage to enemies in range, and continuously deals damage for aperiod of time.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzch601v8qyd5c18zedsi', 'pei', 'Pei', 'Ultimate', 'Tiger Form', 'Switches to tiger form, gaining Movement Speed and enhancing the next 2 Basic Attacks. The 1st Basic Attack lets him dash toward a locked-on target, damaging and slowing them. The 2nd Basic Attack deals magical damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzch601vaqyd5k7viq7yf', 'pei', 'Pei', 'Ultimate', 'Beastly Instincts', 'Gains extra Physical Attack, Physical Defense, Magical Defense, and Movement Speed while in tiger form.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzch601vcqyd5dpu3h916', 'pei', 'Pei', 'Ultimate', 'Roaring Tiger Stance', 'Bites enemies, dealing damage. Restores Energy when this attack kills the enemy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzch701veqyd59sh8lyju', 'pei', 'Pei', 'Ultimate', 'Leaping Tiger Stance', 'Pounces in the target direction. lf runs into terrain, latches onto it brieflyand can pounce again.lf the pounce hits an enemy, he damages, recovers Energy, and reduces this skill''s cooldown.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzch701vgqyd51yv2z8qt', 'pei', 'Pei', 'Ultimate', 'Human Form', 'Switches to human form, gains Movement Speed and enhances the next Basic Attack. Deals damage to the target and enemies in a cone-shaped area behind them.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzchd01vvqyd5xxf7v43w', 'sakeer', 'Sakeer', 'Passive', 'Firefly Protection', 'Basic Attacks and skills summon fireflies that deal extra damage to enemies and grant vision of them. Periodically heals teammates. Can charge up his Basic Attack to heal himself.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzchd01vxqyd5pabwwcun', 'sakeer', 'Sakeer', '1', 'Mulberry Power', 'Launches and damages enemies in front while summoning fireflies to heal teammates or damage enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzche01vzqyd563mna4f3', 'sakeer', 'Sakeer', '2', 'Ride the Wind', 'Flies to a brush while summoning fireflies that heal teammates or damage enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzche01w1qyd5qedg5nii', 'sakeer', 'Sakeer', 'Ultimate', 'Firefly Fields', 'Summons a brush and can fly into it by using this skill again. The brush summons fireflies over time that heal teammates or damage enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzchj01weqyd56zz8ycfa', 'shangguan', 'Shangguan', 'Passive', 'Piercing Brush', 'Enhances every 3rd Basic Attack, causing it to deal pierce damage. Deals damage when brush strokes of different skills come in contact. Touching Brush Power grants enhanced Basic Attack and Health restoration.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzchk01wgqyd56a0s487q', 'shangguan', 'Shangguan', '1', 'Ink Burst', 'Swipes the brush in the target direction, dealing damage to enemies in the path. Extra damage is dealt at max distance.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzchk01wiqyd5ooc3xttg', 'shangguan', 'Shangguan', '2', 'Seething Script', 'Summons a brush to write at the target location, dealing damage andslowing enemies in the path.', '[]', '[]', NULL, NULL, '', '');
