INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcht01x9qyd5auujfbxx', 'shi', 'Shi', 'Passive', 'Maiden''s Trick', 'The farther away the enemy is, the more damage skills deal.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcht01xbqyd58zzltngj', 'shi', 'Shi', '1', 'Silk Imprint', 'Throws her artifact, damaging enemies and pulling them toward it. Can be used again to pull the enemy in the target direction.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzchu01xdqyd5hisx3w2s', 'shi', 'Shi', '2', 'Silky Beauty', 'Releases an energy orb that continuously deals damage to enemies within range for a short time, and then explodes to deal additional damage. Enemies are slowed the first time the orb hits them.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzchu01xfqyd50zjpdya1', 'shi', 'Shi', 'Ultimate', 'Sole Focus', 'Resets Skill 2''s cooldown and enhances herself. While enhanced, gains Movement Speed and reduces Skill 2''s cooldown by half. Skill 1 can pull the enemy twice.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzci101y4qyd5599ukqnk', 'shouyue', 'Shouyue', 'Passive', 'Accuracy', 'Basic Attacks deal extra damage, and Critical Rate is converted into Physical Attack. Extra Critical Rate increases Basic Attack damage. When out of combat and next to a wall, gains disguise and Movement Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzci201y6qyd57h8q35ng', 'shouyue', 'Shouyue', '1', 'The Tranquil Eye', 'Plants a device that continuously grants vision Passive: Gains increased Physical Pierce when standing still, but loses it when moving.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzci201y8qyd5boo12xh6', 'shouyue', 'Shouyue', '2', 'Wild Wind', 'Fires in the target direction, damaging and slowing the target hit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzci301yaqyd5f693u4fk', 'shouyue', 'Shouyue', 'Ultimate', 'Getaway', 'Leaps backwards and fires in the target direction, damaging and slowing the target hit while gaining Movement Speed. Rounds stocked are shared with Skill 2. Passive: Increases Basic Attack range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcia01yzqyd57116joxb', 'sima-yi', 'Sima Yi', 'Passive', 'Quiet Whispers', 'Gains vision of casters within range. Using this skill will enhance his Basic Attack and deal damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcib01z1qyd5cz2xad64', 'sima-yi', 'Sima Yi', 'Ultimate', 'Death Descends', 'Releases a shockwave over the target area, dealing damage to enemies upon landing.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcii01zmqyd52j6ejrvr', 'sun-bin', 'Sun Bin', 'Passive', 'Hourglass of Time', 'Gains a Movement Speed bonus after using skills.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcii01zoqyd5vjdrlrc8', 'sun-bin', 'Sun Bin', '1', 'Time Bomb', 'Fires a bomb in the target direction, which deals damage and attaches itself to the hit enemy. After a brief delay, inflicts AoE damage and slow.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcij01zqqyd51wg9uo1d', 'sun-bin', 'Sun Bin', '2', 'Time Flux', 'Timebender and nearby teammates within range gain increased Movement Speed. When the effect ends, restores Health equal to 25% of the damage taken while the effect was active. Passive: Gains Cooldown Reduction.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcij01zsqyd5qgxch7ci', 'sun-bin', 'Sun Bin', 'Ultimate', 'Time Lapse', 'Throws a bomb in the target direction, inflicting AoE damage, slow, and silence upon coming in contact with an enemy or reaching its max range. After a brief delay, the bomb deals AoE damage again.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzciq0209qyd53daaf6z9', 'sun-ce', 'Sun Ce', 'Passive', 'Raging Tide', 'The next Basic Attack periodically deals extra damage and restores Health Gains 1 stack every time the skill deals damage, or every time he receives physical or true damage (up to 10 stacks). Each stack increases Physical Defense.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzciq020bqyd53b9653mc', 'sun-ce', 'Sun Ce', '1', 'Wave Render', 'Dashes in the target direction, dealing damage to enemies in his path and dealing AoE damage on arrival. After a short delay, launches enemies and deals them damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzciq020dqyd5d5nzsf8f', 'sun-ce', 'Sun Ce', '2', 'Typhoon', 'Strides forward and sweeps enemies in front, dealing damage and slowing them. Sweeps an extra 2 times before the skill goes into cooldown.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcir020fqyd5i9dib8pu', 'sun-ce', 'Sun Ce', 'Ultimate', 'Set Sail!', 'Pilots a boat forward while lmmune. lt can carry 1 teammate. When it runs into terrain or certain enemies, it explodes, damages, launches, and sunders. lf he bails out early, it''ll coast for a bit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzciy0214qyd5442j8pfe', 'ukyo-tachibana', 'Ukyo Tachibana', 'Passive', 'CONCEALED SABRE HAZY BLADE', 'Every 5–4s, Ukyo Tachibana gains one enhanced Basic Attack that has increased range, restores Health, deals extra damage, and slows enemies. Dealing skill damage shortens the enhanced Basic Attack''s cooldown.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzciy0216qyd5575jfy7i', 'ukyo-tachibana', 'Ukyo Tachibana', '1', 'CONCEALED SABRE SWALLOW SWIPE', 'Ukyo Tachibana creates a domain around himself, then leaps backward, dealing damage to enemies in his path. This skill can be used again after 2s, or immediately if it hits a target. If he returns to the starting point of phase 1 after using phase 2, phase 2 is enhanced.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzciz0218qyd5428oenjd', 'ukyo-tachibana', 'Ukyo Tachibana', '2', 'CONCEALED SABRE HEAVENLY HACK', 'Slashes in the target direction, dealing damage to enemies within range. Enemies at the edge of the skill''s range will be stunned.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzciz021aqyd5ujk7e8gu', 'ukyo-tachibana', 'Ukyo Tachibana', 'Ultimate', 'CONCEALED SABRE SNOWFALL SLASH', 'Slashes 4 times in the target direction, dealing damage to enemies within range. Recovers Health each time damage is dealt.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcj7021zqyd5n70isxw3', 'umbrosa', 'Umbrosa', 'Passive', 'Whirling Featherblades', 'Mark Damage When attacking at a distance, Basic Attacks throw a blade that returns to her. She can hit the blade as it returns to bounce it back at the enemy, dealing increased damage with each rebound. When attacking nearby targets, she enters melee mode and attacks faster. Basic Attacks mark targets. Marked enemies take extra damage from Skill 2.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcj70221qyd5yhbrwrbv', 'umbrosa', 'Umbrosa', '1', 'Feverish Dance', 'Enhance Damage Slow Sweeps the surrounding area, damaging and slowing nearby enemies. Then enters Frenzied state, gaining a major boost to Movement Speed and Attack Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcj80223qyd5n2r4o8gf', 'umbrosa', 'Umbrosa', '2', 'Feathered Tempest', 'Damage Recovery Movement Dashes forward, damaging and knocking back enemies. Also triggers Featherblade marks and spreads them to nearby enemies. Then, throws rebounding blades at enemies in front, dealing damage and recovering Health. Each hit consumes 1 mark to deal extra damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcj80225qyd5xkzih7or', 'umbrosa', 'Umbrosa', 'Ultimate', 'Final Frenzy', 'Indomitable Enhance Damage Damages nearby enemies and gains Movement Speed. Also enters the Indomitable state for 4s, gaining temporary Health. If she is defeated while this skill is not on cooldown, she resurrects after a short delay, damaging nearby enemies. The skill will then enter cooldown. ''''''Passive:'''''' Upgrading this skill increases Skill 2 and melee Basic Attack damage. The Indomitable state ends immediately if she loses all of her temporary Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcjf022uqyd5qor0dwz0', 'wang-zhaojun', 'Wang Zhaojun', 'Passive', 'Frozen Heart', 'Upon leaving combat, gains a shield that chills the attacker when taking damage. When the shield disappears, deals damage to nearby enemies. Every third Basic Attack is enhanced, inflicting extra damage and chill effects.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcjg022wqyd5jp60fo8t', 'wang-zhaojun', 'Wang Zhaojun', '1', 'Shattered Ice', 'Damages and slows enemies in the target area while granting vision of Them.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcjg022yqyd5bt72ahar', 'wang-zhaojun', 'Wang Zhaojun', '2', 'Frigid Prison', 'After a brief delay, freezes enemies in the target area and slows them. Attacks on frozen targets deal extra damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcjg0230qyd5fkp4sn1a', 'wang-zhaojun', 'Wang Zhaojun', 'Ultimate', 'Winter is Here', 'Continuously inflicts damage and slow on enemies in the target area.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcjo023pqyd5ftouo8tm', 'wukong', 'Wukong', 'Passive', 'The Great Sage', 'Using skills enhances the next Basic Attack to a dash strike that deals extra damage. Base Critical Rate increases, but Critical Damage decreases.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcjp023rqyd5jciepcav', 'wukong', 'Wukong', '1', 'Protective Shroud', 'Gains increased Movement Speed and blocks the damage and effects of the next enemy hero skill. After a successful block, gains temporary invulnerability to damage andskills, as well as a shield.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcjp023tqyd5o3zt1cn1', 'wukong', 'Wukong', '2', 'Furious Advance', 'Wukong shifts in the target direction. Hitting units during the shift will trigger another shift and grant a Movement Speed boost. The shift deals damage to monsters, and grievous damage to monsters at low Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcjp023vqyd5rfdz0ddv', 'wukong', 'Wukong', 'Ultimate', 'Golden Cudgel', 'Launches enemies in range, damaging and placing 3 marks on them. BasicAttack removes 1 mark and deals extra damage every time.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcjx024kqyd5qnqg6a1v', 'wuyan', 'Wuyan', 'Passive', 'Petrifying Strike', 'Skills and Basic Attacks have a chance to petrify enemy heroes.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcjx024mqyd5r6iql5h1', 'wuyan', 'Wuyan', '1', 'Storm and Stress', 'Dashes to the target location and enhances the next Basic Attack to inflict extra damage and slow.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcjx024oqyd5le66bfgu', 'wuyan', 'Wuyan', '2', 'Shock and Awe', 'Deals damage to enemies in the specified area.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcjy024qqyd52cwko6pm', 'wuyan', 'Wuyan', 'Ultimate', 'Hurricane Hammer', 'Swings the hammer for a period of time, continuously dealing damage to nearby enemies in range. Gains increased Movement Speed and a shield while the skill is used. Passive: Grants shield periodically.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzck5025bqyd5jlw1hfxe', 'xiang-yu', 'Xiang Yu', 'Passive', 'Resolute Will', 'Gains damage immunity when Health falls below 30%. Basic Attacks deal extra damage to different units every 5s.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzck5025dqyd574w7xb5g', 'xiang-yu', 'Xiang Yu', '1', 'Righteous Fervor', 'Dashes forward and knocks back enemies. At the end of the dash, launches the enemy and deals damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzck6025fqyd51pvwa1nu', 'xiang-yu', 'Xiang Yu', '2', 'No Retreat', 'Slows nearby enemies in range and reduces their damage output while dealing damage.Passive: Gains extra Health for every extra point of Physical Defense.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzck6025hqyd5uun4qz8n', 'xiang-yu', 'Xiang Yu', 'Ultimate', 'Hegemon''s Slash', 'Deals damage to enemies in the target direction. Inflicts extra damage andstun on enemies close by.The lower his Health, the higher the damage.He gains invulnerability whilethe skill is being released, preventing his Health from falling below 1.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzckc0260qyd57h3fphlz', 'xiao-qiao', 'Xiao Qiao', 'Passive', 'Encouraging Thoughts', 'Hitting enemies with skills enhances herself, increasing her Movement Speed.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzckd0262qyd523eu73iq', 'xiao-qiao', 'Xiao Qiao', '1', 'Blossoming Fan', 'Throws fan in the target direction, which returns to her upon reaching max range, damaging enemies in its path both ways.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzckd0264qyd5mu4hkz5u', 'xiao-qiao', 'Xiao Qiao', '2', 'Honeysweet Breeze', 'Deals damage to enemies in the target area and launches them.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcke0266qyd5tr40biig', 'xiao-qiao', 'Xiao Qiao', 'Ultimate', 'Meteor Storm', 'Summons meteors, dealing damage to nearby enemies in range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzckm026vqyd5h6ufno40', 'xuance', 'Xuance', 'Passive', 'Crazed Prelude', 'Deals extra damage to enemies at long range and slows them, while gaining a Movement Speed boost.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzckm026xqyd5si72tgce', 'xuance', 'Xuance', '1', 'Flailing Sickles', 'Dashes in the target direction, pulling enemies marked by his sickle a certain distance. Also enhances his next Basic Attack.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzckn026zqyd5vcxobq5n', 'xuance', 'Xuance', '2', 'Nightmare Hooks', 'Charges up and gains Movement Speed. After charging, he throws the sickle to immobilize enemies and deal damage, marking the first enemy hit. Using the skill again will pull back and damage the marked enemy.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzckn0271qyd5uydld6ea', 'xuance', 'Xuance', 'Ultimate', 'Crimson Blur', 'Dashes behind a target marked by his sickle, dealing damage. Beyond a certain range, he moves toward the target instead. If he has not marked a target, the hook latches onto one, dealing damage. Takes 50% less damage during the dash. Passive: Kills and assists grant Movement Speed and Attack Speed, up to 3 stacks.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzckt027gqyd5ctli08hk', 'yang-jian', 'Yang Jian', 'Passive', 'Mind Games', 'Yang Jian''s Resistance increases for each nearby enemy hero.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzckt027iqyd5cx8nuf41', 'yang-jian', 'Yang Jian', '1', 'Unleash the Hound', 'Yang Jian commands a Heaven Hound to dash in the target direction, marking and dealing damage to the first enemy hit. Upon using again, Yang Jian dashes to the marked enemy and deals damage to them.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcku027kqyd54xstwwbl', 'yang-jian', 'Yang Jian', '2', 'Vain Disillusionment', 'Yang Jian deals damage to enemies in front of him and stuns them while reducing their Movement Speed. if an enemy is hit, his Basic Attack is enhanced to deal extra damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzckv027mqyd5f9niq6c4', 'yang-jian', 'Yang Jian', 'Ultimate', 'Sight of Origin', 'Yang Jian unleashes a beam of light in the target direction, dealing damage and recovering Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcl00281qyd5pckorn8b', 'yango', 'Yango', 'Passive', 'Occult Arts - Manipulation', 'PuppetRecovery Chance gaining Hero Shards and recover Health when attacking. Collect 50 Hero Shards (up until 150 stocks, can auto-stock every certain seconds) to summon the corresponding hero.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcl10283qyd5zt7bt7o6', 'yango', 'Yango', '1', 'Occult Arts - Umbra', 'PuppetCrowd ControlMovement Throws the puppet, dealing damage and launching enemies in the path, then begins controlling the puppet.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcl10285qyd5tdmfdcml', 'yango', 'Yango', '2', 'Occult Arts - Zhi Chu Luan', 'Damage Reduction Tosses paper birds, which deal damage to enemies in their path.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcl20287qyd5hjn3n7ut', 'yango', 'Yango', 'Ultimate', 'Occult Arts - Shadow Crucifixion', 'MovementSlow Releases several strings, dealing damage to targets hit. Repeated hits additionally inflict slow.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcl20289qyd5gw8sf9xp', 'yango', 'Yango', 'Ultimate', 'Occult Arts - Dispersal', 'MovementCleanse Vanishes, cleansing all crowd control effects, then reappearing in the target location after a brief delay.', '[]', '[]', NULL, NULL, '', '');
