INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzclo02a7qyd5m48kfdda', 'yaria', 'Yaria', 'Passive', 'Deer Spirit', 'When inflicted with crowd control effects (excluding suppression), gains immunity to all effects.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzclp02a9qyd5gs8v8ds3', 'yaria', 'Yaria', '1', 'Wandering Beam', 'Releases a spirit in the target direction, which tracks nearby enemies after reaching its max range.The spirit launches and deals damage to enemies hit. In deer spirit form, using this skill will restore her to Human Form.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzclp02abqyd5bvt60o9r', 'yaria', 'Yaria', '2', 'Accelerating Blitz', 'Deals continuous damage to nearby enemies. Attached: Increases casting range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzclq02adqyd53wcb5h5j', 'yaria', 'Yaria', 'Ultimate', 'Verdant Protector', 'Attaches herself to a teammate, providing a true damage shield and enhancing your skill effects. Attached: When the shield is exhausted, the attachment will end and enter cooldown. Actively detaching reduces the cooldown of this skill.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzclw02auqyd52460bdvt', 'ying', 'Ying', 'Passive', 'Spear Will - Sweeping Fire', 'Skills grant marks (up to 3 stacks), and different stacks upgrade thefollowing Basic Attacks into different skills.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzclx02awqyd5vp5ryf1k', 'ying', 'Ying', '1', 'Moonslash', 'Deals damage to enemies within range and launches them.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzclx02ayqyd5qwg113gl', 'ying', 'Ying', '2', 'Cloudchaser', 'Dashes to the target location then sweeps the enemy, slowing them and dealing damage. Skill can be charged to enhance damage and gain extra effects', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcly02b0qyd5joldxkog', 'ying', 'Ying', 'Ultimate', 'Starburn', 'Dashes in the target direction, damaging and launching enemies. Then returns to the start point to damage and pull enemies a short distance. Gains lmmunity and damage reduction while using. Use again to deal continuous damage to the target area.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcly02b2qyd51xxwdccx', 'ying', 'Ying', 'Ultimate', 'Stalwart - Peacemaker', 'Continuously deals damage to enemies within range and gains a shield.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcly02b4qyd5lxnpbt2r', 'ying', 'Ying', 'Ultimate', 'Zealous - Devastation', 'Delivers 3 consecutive attacks, dealing damage and recovering Health.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzclz02b6qyd511zgqocd', 'ying', 'Ying', 'Ultimate', 'Zenith - Wildfire', 'Gains Movement Speed and damage reduction, and can ignore terrain. Then deals damage to enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcm802bxqyd5v0qvjb72', 'yixing', 'Yixing', 'Passive', 'Maintaining Initiative', 'Basic Attacks deal magical damage. For every 4 skill hits on the same enemy, generates a Weiqi stone that deals magical damage and adds to the total number of Weiqi stones. Gains brief immunity to all damage and increased Movement Speed upon taking fatal damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcm802bzqyd5abwiynlk', 'yixing', 'Yixing', '1', 'Sliding Stones', 'Places a Weiqi stone at the target location, gaining vision and damaging enemies. Weiqi stones will be pulled into Skill 2''s Weiqi formation, damaging and slowing enemies in their path.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcm802c1qyd5e7cdghkv', 'yixing', 'Yixing', '2', 'Taking Liberties', 'Deals damage to the target area and creates a Weiqi formation. The formation pulls enemies toward its center, damaging them in the process.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcm902c3qyd5txqsjhhc', 'yixing', 'Yixing', 'Ultimate', 'The World is My Board', 'Draws a Weiqi board that launches enemies and places marks on them while exposing their location. Enemies caught within the Weiqi board are bound and will be unable to leave. When the Weiqi board is fully formed, his Movement Speed is increased.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmh02csqyd53cnf793d', 'yuhuan', 'Yuhuan', 'Passive', 'Poignant Melodies', 'Changes the melody to produce different skill effects.
War: Skills deal damage to nearby enemies.
Peace: Skills heal nearby allies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmh02cuqyd5ybb2p0o9', 'yuhuan', 'Yuhuan', '1', 'Tragic Beauty', 'Damages and slows nearby targets. Her next Basic Attack will deal more damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmh02cwqyd54ye7rfw2', 'yuhuan', 'Yuhuan', '2', 'Mournful Tempo', 'Gains Movement Speed, and after a brief delay, inflicts damage and stun on enemies in the target area.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmi02cyqyd548gby2dj', 'yuhuan', 'Yuhuan', 'Ultimate', 'Melody of Peace', 'Changes the melody to Peace, in which skills restore Health to nearby allies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmo02ddqyd522p3x1kk', 'zhang-fei', 'Zhang Fei', 'Passive', 'Dark Potential', 'Human Form: Hits from Basic Attacks and skills grant madness. Ferali Form: Casting the skill reduces the Movement Speed of enemies in range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmo02dfqyd5eaznv0l5', 'zhang-fei', 'Zhang Fei', '1', 'Forbidden Domain', 'Deals damage to enemies in range. Knocks back enemy heroes.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmo02dhqyd5qjzg9bgo', 'zhang-fei', 'Zhang Fei', '2', 'Leaping Savior', 'Jumps to the target location, granting a shield to nearby teammates. Gains extra Madness for every teammate he shields.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmp02djqyd5e9n6lu8f', 'zhang-fei', 'Zhang Fei', 'Ultimate', 'Unbridled Outburst', 'Roars and transforms, gaining brief Invincibility, then a shield. The roar forms a gust of wind that damages, knocks back, and stuns enemies. While inside the wind, Zhang Fei gains increased Movement Speed', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmp02dlqyd5ac00oz9t', 'zhang-fei', 'Zhang Fei', 'Ultimate', 'Mad Slaughter', 'Deals damage to targets ahead.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmp02dnqyd5c4j6icp1', 'zhang-fei', 'Zhang Fei', 'Ultimate', 'Stampede', 'Jumps to the target area, dealing damage to nearby enemies.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmw02e6qyd5i50bcga5', 'zhou-yu', 'Zhou Yu', 'Passive', 'Blaze', 'Damage from Basic Attacks and skills apply marks to enemy units andstructures. At 4 stacks, targets are slowed and suffer damage over time.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmw02e8qyd54l5xpmty', 'zhou-yu', 'Zhou Yu', '1', 'Wildfire', 'Invokes a wind domain in the target direction, slowing and knocking back enemies in range. Nearby teammates gain Move Speed, and his nearby fires will spread in the direction of the wind.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmx02eaqyd55kcej9c1', 'zhou-yu', 'Zhou Yu', '2', 'Scorching Bolt', 'Creates a fire domain at the target location that deals burning damage toenemies in it. There can be up to 5 fire domains at a time. He recovers Health over time while in a fire domain. Can stock up to 3 charges of this skill.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcmx02ecqyd5tmfegchf', 'zhou-yu', 'Zhou Yu', 'Ultimate', 'Flames of War', 'Deals damage to enemies in range. lf there''s a fire zone in range, any enemies within it will be stunned and take extra damage.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcn202enqyd5512kv4yk', 'zhuangzi', 'Zhuangzi', 'Passive', 'Nature''s Will', 'Periodically removes crowd control effects and increases Movement Speed and damage reduction.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcn302epqyd5a53goton', 'zhuangzi', 'Zhuangzi', '1', 'Kaleidoscope', 'Triggers Nature''s Will, releasing dream butterflies in a fan-shaped area, inflicting damage and slowing enemies in range.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcn302erqyd5y93czez4', 'zhuangzi', 'Zhuangzi', '2', 'Sleep Starts', 'Deals damage to enemies in range and increases ally Movement Speed Grants a stack each time dealing damage, up to 5 stacks. Each stack increases skill damage. Passive: Periodically casts Sleep Starts.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcn402etqyd5w94lff3o', 'zhuangzi', 'Zhuangzi', 'Ultimate', 'Butterfly Effect', 'Removes crowd controls from allies within range and increases shield.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcna02f8qyd5qzswfsn9', 'zilong', 'Zilong', 'Passive', 'Dragon''s Roar', 'The lower his Health, the greater his damage reduction and skills.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcna02faqyd5vkwn1f2l', 'zilong', 'Zilong', '1', 'Thunderbreaker', 'Zilong charges forward, dealing damage and enhancing his next Basic Attack. This skill''s cooldown is reset whenever his Health reaches a certain level.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcna02fcqyd5ch54veg2', 'zilong', 'Zilong', '2', 'Stormpiercer', 'Jabs repeatedly in the target direction, dealing damage. Recovers Health on hit.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcnb02feqyd5nd2ytfgk', 'zilong', 'Zilong', 'Ultimate', 'Skysplitter', 'Leaps to the target area, damaging and launching enemies in the center.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcnh02ftqyd5fsruw4b3', 'ziya', 'Ziya', 'Passive', 'Sanctification (Ziya)', 'When Ziya deals damage to a target and they are defeated within 4s, he gains EXP. When reaching level, he gains Sanctify, and increases his level cap to 25. Sanctify allows him to increase a teammate''s level cap, and potentially earn EXP.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcnh02fvqyd5ej38z19x', 'ziya', 'Ziya', '1', 'Divine Seal', 'Seals enemies within range, dealing magical damage while reducing their Movement Speed, Physical and Magical Defense for 3.5s. If the skill hits an enemy, he gains a Movement Speed boost.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcnh02fxqyd5fgabhj4u', 'ziya', 'Ziya', '2', 'Divine Punishment', 'Conjures a magic circle that deals 3 strikes of damage to nearby enemies. After a short delay, the magic circle explodes, dealing extra magical damage and launching enemies for 0.8s.', '[]', '[]', NULL, NULL, '', '');
INSERT OR REPLACE INTO skills (skill_id, hero_slug, hero_name, slot, name, description, damage_values, cooldown, mana_cost, cast_range, patch_added, last_updated) VALUES ('cmqnmzcni02fzqyd53obyb1ws', 'ziya', 'Ziya', 'Ultimate', 'Universal Law', 'Unleashes 3 shockwaves to deal magical damage. Reaching level 15 increases the Ultimate''s charging speed by 10% and grants a chance to allow him to move after initiating the charge.', '[]', '[]', NULL, NULL, '', '');
